// ── DB 초기화: 샘플 데이터 없으면 삽입 ──
async function initDb(env: any) {
  const sql = getDb(env)
  try {
    // 테이블 생성
    await sql`CREATE TABLE IF NOT EXISTS shops (
      id TEXT PRIMARY KEY, name TEXT NOT NULL, slug TEXT, category TEXT,
      location TEXT, address TEXT, google_map_url TEXT, google_map_embed TEXT,
      price_range TEXT, hours TEXT, services JSONB DEFAULT '[]',
      service_prices JSONB DEFAULT '[]', description TEXT,
      rating REAL DEFAULT 5.0, review_count INTEGER DEFAULT 0,
      thumbnail TEXT, photos JSONB DEFAULT '[]', commission INTEGER DEFAULT 15,
      active BOOLEAN DEFAULT true, created_at TEXT
    )`
    // photos 컬럼 없으면 추가 (기존 DB 마이그레이션)
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS photos JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS lat TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS lng TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS reviews JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS google_place_id TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS meta_description TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS seo_keywords TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS why_choose JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS menu_items JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS review_summary JSONB DEFAULT NULL` } catch(e) {}
    try { await sql`ALTER TABLE shops ADD COLUMN IF NOT EXISTS editor_note TEXT DEFAULT ''` } catch(e) {}
    // ── blog_posts 테이블 ──
    await sql`CREATE TABLE IF NOT EXISTS blog_posts (
      id TEXT PRIMARY KEY,
      slug TEXT UNIQUE NOT NULL,
      title TEXT NOT NULL,
      meta_description TEXT DEFAULT '',
      content TEXT DEFAULT '',
      excerpt TEXT DEFAULT '',
      category TEXT DEFAULT '',
      area TEXT DEFAULT '',
      tags JSONB DEFAULT '[]',
      cover_image TEXT DEFAULT '',
      status TEXT DEFAULT 'draft',
      views INTEGER DEFAULT 0,
      shop_id TEXT DEFAULT NULL,
      created_at TEXT,
      updated_at TEXT
    )`
    // blog_posts 기존 테이블에 shop_id 컬럼 없으면 추가
    try { await sql`ALTER TABLE blog_posts ADD COLUMN IF NOT EXISTS shop_id TEXT DEFAULT NULL` } catch(e) {}
    await sql`CREATE TABLE IF NOT EXISTS videos (
      id TEXT PRIMARY KEY, shop_id TEXT REFERENCES shops(id) ON DELETE CASCADE,
      title TEXT, description TEXT, video_url TEXT, thumbnail TEXT,
      tags JSONB DEFAULT '[]', views INTEGER DEFAULT 0,
      likes INTEGER DEFAULT 0, created_at TEXT,
      video_url_low TEXT, video_url_mid TEXT, video_url_high TEXT
    )`
    // 기존 테이블에 컬럼이 없으면 추가 (ALTER TABLE은 이미 있으면 에러 → try/catch)
    try { await sql`ALTER TABLE videos ADD COLUMN IF NOT EXISTS video_url_low TEXT` } catch(e) {}
    try { await sql`ALTER TABLE videos ADD COLUMN IF NOT EXISTS video_url_mid TEXT` } catch(e) {}
    try { await sql`ALTER TABLE videos ADD COLUMN IF NOT EXISTS video_url_high TEXT` } catch(e) {}
    try { await sql`ALTER TABLE videos ADD COLUMN IF NOT EXISTS instagram_url TEXT DEFAULT ''` } catch(e) {}
    await sql`CREATE TABLE IF NOT EXISTS bookings (
      id TEXT PRIMARY KEY, shop_id TEXT, shop_name TEXT, name TEXT,
      email TEXT, phone TEXT, service TEXT, people TEXT DEFAULT '1',
      date TEXT, message TEXT, status TEXT DEFAULT 'new',
      commission_rate INTEGER DEFAULT 10, estimated_amount TEXT, created_at TEXT
    )`
    // 영상 IP별 조회수 중복 방지 로그 테이블
    await sql`CREATE TABLE IF NOT EXISTS video_views_log (
      id TEXT PRIMARY KEY,
      video_id TEXT NOT NULL,
      viewer_ip TEXT NOT NULL,
      viewed_at TEXT NOT NULL
    )`
    try { await sql`CREATE UNIQUE INDEX IF NOT EXISTS uq_video_ip ON video_views_log(video_id, viewer_ip)` } catch(e) {}

    // ── 방문자 행동 이벤트 테이블 ──
    await sql`CREATE TABLE IF NOT EXISTS visitor_events (
      id TEXT PRIMARY KEY,
      session_id TEXT NOT NULL,
      visitor_id TEXT NOT NULL,
      event TEXT NOT NULL,
      page TEXT DEFAULT '',
      target TEXT DEFAULT '',
      value TEXT DEFAULT '',
      shop_id TEXT DEFAULT '',
      shop_name TEXT DEFAULT '',
      duration INTEGER DEFAULT 0,
      scroll_pct INTEGER DEFAULT 0,
      referrer TEXT DEFAULT '',
      ua TEXT DEFAULT '',
      country TEXT DEFAULT '',
      created_at TIMESTAMPTZ DEFAULT NOW()
    )`
    try { await sql`CREATE INDEX IF NOT EXISTS idx_ve_session ON visitor_events(session_id)` } catch(e) {}
    try { await sql`CREATE INDEX IF NOT EXISTS idx_ve_visitor ON visitor_events(visitor_id)` } catch(e) {}
    try { await sql`CREATE INDEX IF NOT EXISTS idx_ve_created ON visitor_events(created_at DESC)` } catch(e) {}

    // ── 방문자 세션 요약 테이블 ──
    await sql`CREATE TABLE IF NOT EXISTS visitor_sessions (
      session_id TEXT PRIMARY KEY,
      visitor_id TEXT NOT NULL,
      first_page TEXT DEFAULT '',
      referrer TEXT DEFAULT '',
      ua TEXT DEFAULT '',
      country TEXT DEFAULT '',
      device TEXT DEFAULT '',
      started_at TIMESTAMPTZ DEFAULT NOW(),
      last_active TIMESTAMPTZ DEFAULT NOW(),
      page_count INTEGER DEFAULT 0,
      event_count INTEGER DEFAULT 0,
      wa_clicked BOOLEAN DEFAULT false,
      max_scroll INTEGER DEFAULT 0
    )`
    try { await sql`CREATE INDEX IF NOT EXISTS idx_vs_visitor ON visitor_sessions(visitor_id)` } catch(e) {}
    try { await sql`CREATE INDEX IF NOT EXISTS idx_vs_started ON visitor_sessions(started_at DESC)` } catch(e) {}

    // shops_ja — 일본어판 업체 테이블
    await sql`CREATE TABLE IF NOT EXISTS shops_ja (
      id TEXT PRIMARY KEY, name TEXT NOT NULL, slug TEXT, category TEXT,
      location TEXT, address TEXT, google_map_url TEXT, google_map_embed TEXT,
      price_range TEXT, hours TEXT, services JSONB DEFAULT '[]',
      service_prices JSONB DEFAULT '[]', description TEXT,
      meta_description TEXT DEFAULT '', seo_keywords TEXT DEFAULT '',
      seo_text TEXT DEFAULT '', why_choose JSONB DEFAULT '[]',
      rating REAL DEFAULT 5.0, review_count INTEGER DEFAULT 0,
      thumbnail TEXT, photos JSONB DEFAULT '[]', commission INTEGER DEFAULT 15,
      active BOOLEAN DEFAULT true, created_at TEXT,
      lat TEXT DEFAULT '', lng TEXT DEFAULT '',
      reviews JSONB DEFAULT '[]', google_place_id TEXT DEFAULT '',
      menu_items JSONB DEFAULT '[]', review_summary JSONB DEFAULT NULL,
      editor_note TEXT DEFAULT '', whatsapp TEXT DEFAULT ''
    )`
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS lat TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS lng TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS reviews JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS google_place_id TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS meta_description TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS seo_keywords TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS seo_text TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS why_choose JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS menu_items JSONB DEFAULT '[]'` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS review_summary JSONB DEFAULT NULL` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS editor_note TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS whatsapp TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS google_map_embed TEXT DEFAULT ''` } catch(e) {}
    try { await sql`ALTER TABLE shops_ja ADD COLUMN IF NOT EXISTS photos JSONB DEFAULT '[]'` } catch(e) {}

    // blog_posts_ja — 일본어판 블로그 테이블
    await sql`CREATE TABLE IF NOT EXISTS blog_posts_ja (
      id TEXT PRIMARY KEY,
      slug TEXT UNIQUE NOT NULL,
      title TEXT NOT NULL,
      meta_description TEXT DEFAULT '',
      content TEXT DEFAULT '',
      excerpt TEXT DEFAULT '',
      category TEXT DEFAULT '',
      area TEXT DEFAULT '',
      tags JSONB DEFAULT '[]',
      cover_image TEXT DEFAULT '',
      status TEXT DEFAULT 'draft',
      views INTEGER DEFAULT 0,
      shop_id TEXT DEFAULT NULL,
      created_at TEXT,
      updated_at TEXT
    )`

    // 샘플 데이터 삽입 (비어있을 때만)
    const cnt = await sql`SELECT COUNT(*) as c FROM shops`
    if (Number(cnt[0].c) === 0) {
      for (const s of shops) {
        await sql`INSERT INTO shops VALUES (
          ${s.id},${s.name},${s.slug},${s.category},${s.location},${s.address},
          ${s.googleMapUrl},${s.googleMapEmbed},${s.priceRange},${s.hours},
          ${JSON.stringify(s.services)},${JSON.stringify(s.servicePrices)},
          ${s.description},${s.rating},${s.reviewCount},${s.thumbnail},
          ${s.commission},${s.active},${s.createdAt}
        ) ON CONFLICT (id) DO NOTHING`
      }
      for (const v of videos) {
        await sql`INSERT INTO videos VALUES (
          ${v.id},${v.shopId},${v.title},${v.description},${v.videoUrl},
          ${v.thumbnail},${JSON.stringify(v.tags)},${v.views},${v.likes},${v.createdAt}
        ) ON CONFLICT (id) DO NOTHING`
      }
    }
  } catch(e) { console.error('initDb error:', e) }
}

// ── lazy init: 첫 요청 시 1회만 실행 ──
let _dbInited = false
async function ensureDb(env: any) {
  if (_dbInited) return
  _dbInited = true
  try {
    await initDb(env)
  } catch(e) {
    _dbInited = false  // 실패 시 재시도 허용
    throw e
  }
}

