// ── AI SEO 설명 자동생성 ──
app.post('/api/ai-seo', async (c) => {
  try {
    const body = await c.req.json()
    const { name, location, category, services, priceRange, hours, placeId, rating, reviewCount } = body
    if (!name) return c.json({ error: 'name required' }, 400)

    // 카테고리별 외국인 검색 키워드
    const catKeywords: Record<string,string> = {
      skincare: 'Korean skincare Seoul, facial treatment Seoul, glass skin Seoul, K-beauty facial, skin clinic Seoul foreigners',
      makeup:   'Korean makeup Seoul, K-beauty makeup artist, Korean beauty look, makeup studio Seoul foreigners',
      hair:     'Korean hair salon Seoul, K-pop hairstyle Seoul, hair coloring Seoul foreigners, balayage Seoul, Korean hair dyeing',
      headspa:  'head spa Seoul, Korean head spa foreigners, scalp treatment Seoul, Korean scalp massage, head spa Seoul English',
      clinic:   'Korean dermatology Seoul, skin clinic Seoul foreigners, laser treatment Seoul, aesthetic clinic Korea, Korean skin care clinic',
      spa:      'Korean spa Seoul, body treatment Seoul foreigners, Korean massage Seoul, relaxation spa Seoul English',
    }
    const catKeyword = catKeywords[category] || 'Korean beauty Seoul, K-beauty'
    const area = (location || 'Seoul').split(',')[0].trim()

    // 브랜드 검색 변형 자동 생성
    // "Moclock" → "Moclock Seoul", "Moclock head spa", "Moclock booking", "Moclock review", "Moclock foreigner"
    const brandVariants = [
      `${name} Seoul`,
      `${name} ${category}`,
      `${name} booking`,
      `${name} review`,
      `${name} foreigner`,
      `${name} English`,
      `${name} price`,
      `${name} ${area}`,
    ].join(', ')

    const ratingInfo = rating ? `- Google Rating: ${rating}/5 (${reviewCount || 0} reviews)` : ''
    const serviceList = Array.isArray(services) ? services.join(', ') : (services || 'beauty services')

    const prompt = `You are an SEO expert for a Korean beauty booking platform targeting foreign tourists in Seoul.

The shop "${name}" is a real, well-known ${category} salon in ${area}, Seoul.
Some tourists already search for this shop by name (brand searches).
Your job is to create SEO content that captures BOTH:
1. Brand searches: people who already know "${name}" and search for it
2. Generic searches: people looking for "best ${category} ${area} Seoul foreigners"

Shop details:
- Name: ${name}
- Area: ${area}, Seoul, South Korea
- Category: ${category}
- Services: ${serviceList}
- Price Range: ${priceRange || 'contact for pricing'}
${ratingInfo}
- Brand keyword variations: ${brandVariants}
- Category keywords: ${catKeyword}

Rules:
1. title (titleSuffix): max 40 chars — use format like "${name} | ${area} ${category} Seoul" — must include shop name
2. metaDescription: 140-155 chars — start with shop name, include area + category + "English-friendly" + "Book via WhatsApp"
3. description: 2-3 natural sentences (180-240 chars) — mention shop name naturally, include area, category, what makes it special for foreigners
4. keywords: exactly 8 strings — mix of brand keywords (${name} Seoul, ${name} booking, ${name} review) AND generic keywords (best ${category} ${area} Seoul, ${category} Seoul foreigners, English speaking ${category} Seoul)
5. No quotes inside text values, no markdown, no special characters

Return ONLY valid JSON:
{"titleSuffix":"...","metaDescription":"...","description":"...","keywords":["k1","k2","k3","k4","k5","k6","k7","k8"]}`

    const OPENAI_KEY = c.env?.GSK_TOKEN || c.env?.gsk_token || c.env?.GENSPARK_TOKEN || c.env?.genspark_token || ''
    if (!OPENAI_KEY) return c.json({ error: 'API key not configured' }, 500)
    const res = await fetch('https://www.genspark.ai/api/llm_proxy/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${OPENAI_KEY}`
      },
      body: JSON.stringify({
        model: 'claude-haiku-4-5',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 3000
      })
    })
    if (!res.ok) {
      const err = await res.text()
      return c.json({ error: 'AI API error', detail: err }, 500)
    }
    const data: any = await res.json()
    const text = data.choices?.[0]?.message?.content || ''
    if (!text) return c.json({ error: 'empty response from AI' }, 500)
    // JSON 파싱 (마크다운 코드블록 제거)
    const cleaned = text.replace(/```json\n?/g,'').replace(/```\n?/g,'').trim()
    const jsonMatch = cleaned.match(/\{[\s\S]*\}/)
    if (!jsonMatch) return c.json({ error: 'parse error', raw: text }, 500)
    const result = JSON.parse(jsonMatch[0])
    return c.json(result)
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── AI 요금표 사진 분석 → servicePrices 추출 ──
app.post('/api/parse-price-image', async (c) => {
  try {
    const body = await c.req.json() as { imageUrl: string }
    const { imageUrl } = body
    if (!imageUrl) return c.json({ error: 'imageUrl required' }, 400)

    const OPENAI_KEY = c.env?.GSK_TOKEN || c.env?.gsk_token || c.env?.GENSPARK_TOKEN || c.env?.genspark_token || ''
    if (!OPENAI_KEY) return c.json({ error: 'API key not configured' }, 500)

    const prompt = `You are a price menu OCR assistant for Korean beauty salons.
Look at this price menu image and extract all service names and prices.

Rules:
- Extract EVERY service item you can see
- Convert Korean service names to English (e.g. 보톡스→Botox, 필러→Filler, 리프팅→Lifting, 레이저→Laser, 스킨케어→Skincare, 헤어→Hair, 네일→Nail, 페이셜→Facial)
- For prices: remove commas, keep numbers only (e.g. 80,000원 → 80000)
- If price shows a range like 80,000~150,000, use the lower value
- If price is unclear or not visible, use 0
- Return ONLY valid JSON array, no explanation

Format:
[{"name":"Service Name","price":80000},{"name":"Service Name 2","price":120000}]`

    const res = await fetch('https://www.genspark.ai/api/llm_proxy/v1/chat/completions', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${OPENAI_KEY}`
      },
      body: JSON.stringify({
        model: 'gpt-4o',
        messages: [{
          role: 'user',
          content: [
            { type: 'text', text: prompt },
            { type: 'image_url', image_url: { url: imageUrl, detail: 'high' } }
          ]
        }],
        max_tokens: 2000
      })
    })

    if (!res.ok) {
      const err = await res.text()
      return c.json({ error: 'AI API error', detail: err }, 500)
    }
    const data: any = await res.json()
    const text = (data.choices?.[0]?.message?.content || '').replace(/```json\n?/g,'').replace(/```\n?/g,'').trim()
    let items: any[] = []
    try { items = JSON.parse(text) } catch(e) {
      // JSON 배열 부분만 추출 시도
      const match = text.match(/\[[\s\S]*\]/)
      if (match) items = JSON.parse(match[0])
    }
    if (!Array.isArray(items)) return c.json({ error: 'Failed to parse items', raw: text }, 500)
    return c.json({ items })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── Google Places API 자동가져오기 (query 또는 placeId 직접) ──
app.post('/api/places-fetch', async (c) => {
  try {
    const body = await c.req.json() as { query?: string; placeId?: string }
    const { query, placeId: directPlaceId } = body

    // ── 공통 헬퍼 ──
    // 한국어 + 일본어 + 한자 모두 포함 (업체명에 한자가 붙어오는 경우 대응)
    const isKorean = (s: string) => /[\uAC00-\uD7A3\u3040-\u30FF\u4E00-\u9FFF]/.test(s)

    // 한국어/일본어/한자 제거 — 영어/숫자/공백/기호만 남김
    const stripKorean = (s: string) =>
      s.replace(/[\uAC00-\uD7A3\u3040-\u30FF\u4E00-\u9FFF]+/g, '').replace(/\s{2,}/g, ' ').trim()

    // 지역명 매핑 (한/영 → 표준 표기)
    const areaMap: [string, string][] = [
      ['apgujeong','Apgujeong'],['압구정','Apgujeong'],
      ['cheongdam','Cheongdam'],['청담','Cheongdam'],
      ['sinsa','Sinsa'],['신사','Sinsa'],['가로수길','Sinsa'],
      ['gangnam','Gangnam'],['강남','Gangnam'],['역삼','Gangnam'],['선릉','Gangnam'],
      ['seocho','Seocho'],['서초','Seocho'],
      ['hongdae','Hongdae'],['홍대','Hongdae'],
      ['hapjeong','Hapjeong'],['합정','Hapjeong'],['상수','Hapjeong'],
      ['mapo','Mapo'],['마포','Mapo'],
      ['itaewon','Itaewon'],['이태원','Itaewon'],['한남','Itaewon'],
      ['yongsan','Yongsan'],['용산','Yongsan'],
      ['myeongdong','Myeongdong'],['명동','Myeongdong'],
      ['jongno','Jongno'],['종로','Jongno'],['인사동','Jongno'],
      ['dongdaemun','Dongdaemun'],['동대문','Dongdaemun'],
      ['seongsu','Seongsu'],['성수','Seongsu'],['성동','Seongsu'],
      ['jamsil','Jamsil'],['잠실','Jamsil'],
      ['songpa','Songpa'],['송파','Songpa'],
      ['yeouido','Yeouido'],['여의도','Yeouido'],
      ['sinchon','Sinchon'],['신촌','Sinchon'],
    ]
    const detectLocation = (text: string): string => {
      const t = text.toLowerCase()
      for (const [kw, val] of areaMap) {
        if (t.includes(kw.toLowerCase())) return `${val}, Seoul`
      }
      return 'Seoul'
    }

    // addressComponents → 깨끗한 영문 주소 조합
    const buildEngAddress = (comps: any[], fallbackAddr: string): string => {
      const get = (...types: string[]) => {
        const c = comps.find((x: any) => types.some(t => x.types?.includes(t)))
        if (!c) return ''
        // shortText, longText 중 한국어 없는 것 선택
        const lt = c.longText || '', st = c.shortText || ''
        return !isKorean(lt) ? lt : !isKorean(st) ? st : ''
      }
      const streetNum  = get('street_number')
      const route      = get('route')
      const sub4       = get('sublocality_level_4')
      const sub3       = get('sublocality_level_3')
      const sub2       = get('sublocality_level_2')
      const sub1       = get('sublocality_level_1')
      const district   = get('administrative_area_level_2','locality')
      const province   = get('administrative_area_level_1')

      const street = [streetNum, route].filter(Boolean).join(' ') || [sub4,sub3,sub2].filter(Boolean).join(' ')
      const neighborhood = sub1
      const parts = [street, neighborhood, district, province, 'South Korea'].filter(Boolean)
      const candidate = parts.join(', ')

      // 조합된 주소에도 한국어가 남아있으면 fallback
      if (isKorean(candidate)) {
        const stripped = stripKorean(fallbackAddr)
        return stripped || 'Seoul, South Korea'
      }
      return candidate || stripKorean(fallbackAddr) || 'Seoul, South Korea'
    }

    // Places API 공통 fieldMask (editorialSummary, primaryType, types 포함)
    const FIELD_MASK_DETAILS = [
      'id','displayName','formattedAddress','shortFormattedAddress',
      'addressComponents','regularOpeningHours','rating','userRatingCount',
      'reviews','photos','websiteUri','internationalPhoneNumber',
      'editorialSummary','primaryType','types'
    ].join(',')
    const FIELD_MASK_SEARCH = FIELD_MASK_DETAILS.split(',').map((f: string) => 'places.' + f).join(',')

    // 장소 단일 조회 (placeId로) — Place Details v1
    const fetchPlaceById = async (pid: string): Promise<any> => {
      const r = await fetch(`https://places.googleapis.com/v1/places/${pid}?languageCode=en`, {
        headers: { 'X-Goog-Api-Key': getGoogleKey(c.env), 'X-Goog-FieldMask': FIELD_MASK_DETAILS }
      })
      if (!r.ok) throw new Error('Place Details error: ' + r.status)
      return r.json()
    }

    // primaryType/types → 우리 카테고리로 매핑
    const detectCategory = (primaryType: string, types: string[]): string => {
      const all = [primaryType, ...(types || [])].map(t => t.toLowerCase())
      if (all.some(t => ['beauty_salon','hair_care','hair_salon','barber_shop'].includes(t))) return 'hair'
      if (all.some(t => ['spa','massage','sauna'].includes(t))) return 'spa'
      if (all.some(t => ['doctor','hospital','medical_lab','physiotherapist','skin_care','plastic_surgeon','dermatologist'].includes(t))) return 'clinic'
      if (all.some(t => ['makeup_artist'].includes(t))) return 'makeup'
      return '' // 감지 불가 → 사용자가 직접 선택
    }

    let place: any

    if (directPlaceId) {
      // placeId 직접 전달 → Place Details 바로 조회
      place = await fetchPlaceById(directPlaceId)
    } else {
      if (!query) return c.json({ error: 'query or placeId required' }, 400)
      // Text Search
      const searchRes = await fetch('https://places.googleapis.com/v1/places:searchText', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'X-Goog-Api-Key': getGoogleKey(c.env),
          'X-Goog-FieldMask': FIELD_MASK_SEARCH
        },
        body: JSON.stringify({ textQuery: query, languageCode: 'en' })
      })
      if (!searchRes.ok) {
        const err = await searchRes.text()
        return c.json({ error: 'Places API error', detail: err }, 500)
      }
      const sd: any = await searchRes.json()
      place = sd.places?.[0]
      if (!place) return c.json({ error: 'No place found' }, 404)
    }

    // ── 업체 영문명: 한국어/일본어/한자 제거 ──
    const rawDisplayName: string = place.displayName?.text || ''
    // 1) '|' 구분자로 split → 비(非)CJK 파트 우선
    const nameParts = rawDisplayName.split(/[|｜]/).map((s: string) => s.trim()).filter(Boolean)
    const engName = nameParts.find((s: string) => !isKorean(s) && s.length > 0)
      || (() => { const stripped = stripKorean(rawDisplayName); return stripped.length > 1 ? stripped : '' })()
      || rawDisplayName

    // ── 영문 주소 ──
    const comps: any[] = place.addressComponents || []
    const engAddress = buildEngAddress(comps, place.formattedAddress || '')

    // ── 지역 (location) — addressComponents sublocality_level_1 우선, 없으면 주소 전체 검색 ──
    const sub1Comp = comps.find((x: any) => x.types?.includes('sublocality_level_1'))
    const sub2Comp = comps.find((x: any) => x.types?.includes('sublocality_level_2'))
    const sub1Text = sub1Comp?.longText || sub1Comp?.shortText || ''
    const sub2Text = sub2Comp?.longText || sub2Comp?.shortText || ''
    // sublocality_level_2 → level_1 → formattedAddress 순으로 시도
    const location = detectLocation(sub2Text) !== 'Seoul'
      ? detectLocation(sub2Text)
      : detectLocation(sub1Text) !== 'Seoul'
      ? detectLocation(sub1Text)
      : detectLocation(engAddress) !== 'Seoul'
      ? detectLocation(engAddress)
      : detectLocation(place.formattedAddress || '')

    // ── 영업시간 ──
    const weekdays: string[] = place.regularOpeningHours?.weekdayDescriptions || []
    const hoursStr = weekdays.join(' | ')

    // ── 업체 소개 (editorialSummary) ──
    const description: string = place.editorialSummary?.text || ''

    // ── 카테고리 자동감지 ──
    const suggestedCategory = detectCategory(place.primaryType || '', place.types || [])

    // ── 리뷰: 영어 우선 (최대 5개) ──
    const rawReviews: any[] = place.reviews || []
    const enReviews   = rawReviews.filter((r: any) => r.text?.languageCode === 'en' && (r.text?.text?.length || 0) > 20)
    const otherReviews = rawReviews.filter((r: any) => r.text?.languageCode !== 'en' && (r.text?.text?.length || 0) > 20)
    const reviews = [...enReviews, ...otherReviews].slice(0, 5).map((r: any) => ({
      author: r.authorAttribution?.displayName || 'Guest',
      rating: r.rating || 5,
      text: r.text?.text || '',
      time: r.relativePublishTimeDescription || ''
    }))

    // ── 사진 URL (최대 10장) — 실제 https:// URL로 변환하여 저장 ──
    const rawPhotos: any[] = place.photos || []
    const photoNames = rawPhotos.slice(0, 10).map((p: any) => p.name || '').filter(Boolean)
    const photos = await resolveGooglePhotos(photoNames, getGoogleKey(c.env))

    return c.json({
      placeId:             place.id || '',
      name:                engName,
      address:             engAddress,
      location,
      phone:               place.internationalPhoneNumber || '',
      website:             place.websiteUri || '',
      hours:               hoursStr,
      weekdayDescriptions: weekdays,
      description,
      suggestedCategory,
      primaryType:         place.primaryType || '',
      rating:              place.rating || 0,
      reviewCount:         place.userRatingCount || 0,
      reviews,
      photos
    })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── Google Places 사진만 가져오기 ──
app.post('/api/places-photos', async (c) => {
  try {
    const { placeId } = await c.req.json() as { placeId: string }
    if (!placeId) return c.json({ error: 'placeId required' }, 400)

    const res = await fetch(`https://places.googleapis.com/v1/places/${placeId}`, {
      headers: {
        'X-Goog-Api-Key': getGoogleKey(c.env),
        'X-Goog-FieldMask': 'photos'
      }
    })
    if (!res.ok) return c.json({ error: 'Places API error' }, 500)
    const data: any = await res.json()
    const rawPhotos: any[] = data.photos || []
    const photoNames3 = rawPhotos.slice(0, 6).map((p: any) => p.name || '').filter(Boolean)
    const photos = await resolveGooglePhotos(photoNames3, getGoogleKey(c.env))
    return c.json({ photos })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── Google Places 사진 프록시 (Referer 제한 우회) ──
// URL: /api/photo?name=places%2FPLACE_ID%2Fphotos%2FPHOTO_REF
app.get('/api/photo', async (c) => {
  const name = c.req.query('name') || ''
  if (!name) return c.text('name required', 400)

  // name에 /media suffix가 포함된 경우 제거 (중복 방지)
  const cleanName = name.replace(/\/media$/, '')
  // 1단계: skipHttpRedirect=true로 photoUri JSON 받기
  const apiUrl = `https://places.googleapis.com/v1/${cleanName}/media?key=${getGoogleKey(c.env)}&maxHeightPx=800&maxWidthPx=800&skipHttpRedirect=true`
  try {
    const res = await fetch(apiUrl)
    const ct = res.headers.get('content-type') || ''

    let imgUrl = ''
    if (ct.includes('application/json')) {
      // JSON에서 photoUri 추출
      const json: any = await res.json()
      imgUrl = json.photoUri || ''
    } else if (res.ok) {
      // 직접 이미지로 온 경우
      const buf = await res.arrayBuffer()
      return new Response(buf, {
        headers: { 'Content-Type': ct || 'image/jpeg', 'Cache-Control': 'public, max-age=86400', 'Access-Control-Allow-Origin': '*' }
      })
    }

    if (!imgUrl) return c.text('no photo uri', 502)

    // 2단계: 실제 lh3.googleusercontent.com 이미지 fetch
    const imgRes = await fetch(imgUrl)
    if (!imgRes.ok) return c.text('img fetch failed: ' + imgRes.status, 502)
    const buf = await imgRes.arrayBuffer()
    const imgCt = imgRes.headers.get('content-type') || 'image/jpeg'
    return new Response(buf, {
      headers: {
        'Content-Type': imgCt,
        'Cache-Control': 'public, max-age=86400',
        'Access-Control-Allow-Origin': '*'
      }
    })
  } catch(e: any) {
    return c.text('proxy error: ' + e.message, 500)
  }
})

// ══════════════════════════════════════════
// ── 원클릭 업체+영상 동시 등록 API ──
// POST /api/quick-register
// body: { gmapUrl, videoUrl, videoUrlLow, videoUrlMid, videoUrlHigh, category }
// → 구글맵 → 업체정보 자동가져오기 + 영상 동시 등록
// ══════════════════════════════════════════
app.post('/api/quick-register', async (c) => {
  try {
    const sql = getDb(c.env)
    const { gmapUrl, videoUrl, videoUrlLow, videoUrlMid, videoUrlHigh, category, instagramUrl } = await c.req.json() as { gmapUrl: string; videoUrl: string; videoUrlLow?: string; videoUrlMid?: string; videoUrlHigh?: string; category: string; instagramUrl?: string }

    if (!gmapUrl) return c.json({ error: '구글맵 URL을 입력해주세요' }, 400)

    // ── STEP 1: 구글맵 URL → 업체 정보 가져오기 ──
    // resolve-gmap 로직 재사용: URL 언팩 → Places API 조회
    // ── STEP 1: resolve-gmap 엔드포인트를 내부 호출하여 완전한 업체 정보 획득 ──
    // (placeToJson 로직 동일하게 재사용 → photos, reviews, description, whyChoose 등 모두 포함)
    let resolvedData: any = null
    try {
      const resolveRes = await fetch(
        new URL('/api/resolve-gmap', new URL(c.req.url).origin).toString(),
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ url: gmapUrl })
        }
      )
      if (resolveRes.ok) {
        const d: any = await resolveRes.json()
        if (d && (d.name || d.address)) resolvedData = d
      }
    } catch(e: any) { console.error('[quick-register] resolve-gmap error:', e?.message) }

    if (!resolvedData || (!resolvedData.name && !resolvedData.address)) {
      return c.json({ error: '구글맵에서 업체 정보를 가져오지 못했습니다. (URL 확인 또는 잠시 후 재시도)' }, 400)
    }

    // ── STEP 1.5: 중복 업체 체크 ──────────────────────────────────────────────
    // 1) place_id 완전 일치
    const placeIdToCheck = resolvedData.placeId || resolvedData.googlePlaceId || ''
    if (placeIdToCheck) {
      const pidRows = await sql`SELECT id, name, slug FROM shops WHERE google_place_id = ${placeIdToCheck} AND active = true LIMIT 1`
      if (pidRows.length > 0) {
        const ex = pidRows[0]
        return c.json({
          error: 'already_exists',
          message: `이미 등록된 업체입니다: "${ex.name}"`,
          existingId: ex.id,
          existingSlug: ex.slug,
          existingName: ex.name
        }, 409)
      }
    }
    // 2) 업체명 유사도 체크 (정규화 후 완전 일치)
    const normalizeName = (s: string) => s.toLowerCase().replace(/[\s\-_.,'()]/g, '').replace(/[\uAC00-\uD7A3\u3040-\u30FF\u4E00-\u9FFF]/g, '')
    const rawNameCheck = resolvedData.name || ''
    const normCheck = normalizeName(rawNameCheck)
    if (normCheck.length > 2) {
      const allNames = await sql`SELECT id, name, slug FROM shops WHERE active = true`
      const matched = allNames.find((r: any) => normalizeName(r.name) === normCheck)
      if (matched) {
        return c.json({
          error: 'already_exists',
          message: `이미 등록된 업체입니다: "${matched.name}"`,
          existingId: matched.id,
          existingSlug: matched.slug,
          existingName: matched.name
        }, 409)
      }
    }
    // ───────────────────────────────────────────────────────────────────────────

    // ── STEP 2: 업체명 정리 — 항상 영문명만 추출 (한글 절대 저장 안 함) ──
    const isKor = (s: string) => /[\uAC00-\uD7A3\u3040-\u30FF\u4E00-\u9FFF]/.test(s)
    const hasEng = (s: string) => /[a-zA-Z]/.test(s)
    const stripCJK2 = (s: string) => s.replace(/[\uAC00-\uD7A3\u3040-\u30FF\u4E00-\u9FFF]+/g,'').replace(/\s{2,}/g,' ').trim()
    const rawName: string = resolvedData.name || ''
    // 구분자(|, ·, -)로 분리 후 영문 파트 우선
    const nameParts = rawName.split(/[|\uff5c·]/).map((s: string) => s.trim()).filter(Boolean)
    const p0clean2 = nameParts[0] ? stripCJK2(nameParts[0]) : ''
    // 1) CJK 제거 후 영문이 2자 이상 남으면 사용
    // 2) 파트 중 영문 포함된 것 사용
    // 3) 전체에서 CJK 제거
    // 4) 한글만 남으면 → address에서 영문 추출 시도, 최후엔 rawName 유지
    let engName = (p0clean2.length > 1 && hasEng(p0clean2) ? p0clean2 : null)
      || nameParts.find((s: string) => hasEng(s) && s.length > 1)
      || (hasEng(stripCJK2(rawName)) ? stripCJK2(rawName) : null)
      || rawName  // 최후 폴백 (한글만인 경우 그대로 — 아래서 처리)
    // 한글만 남아있는 경우: address에서 영문 단어 추출 시도
    if (!hasEng(engName) && resolvedData.address) {
      const addrEng = resolvedData.address.replace(/[^a-zA-Z0-9\s,\-]/g,'').trim()
      // "123 Nonhyeon-ro, Gangnam" 형태에서 동네명만 뽑기
      const addrPart = addrEng.split(',')[1]?.trim() || addrEng.split(' ').slice(1,3).join(' ')
      if (addrPart && addrPart.length > 2) {
        const catLabel: Record<string,string> = {clinic:'Clinic',skincare:'Skincare',hair:'Hair Salon',headspa:'Head Spa',makeup:'Makeup Studio',tattoo:'Tattoo Studio',spa:'Spa'}
        engName = addrPart + ' ' + (catLabel[category||'clinic'] || 'Beauty')
      }
    }

    // ── STEP 3: slug 생성 ──
    // SEO 최적 slug: makeShopSlug 공통 함수 사용 (카테고리 키워드 + 지역명 포함)
    let slug = await makeShopSlug(sql, engName, resolvedData.location || 'seoul', category || 'clinic')

    // ── STEP 4~6: GPT + Google Places로 고유 SEO 자동 생성 ──
    const loc = resolvedData.location || 'Seoul'
    const cat = category || 'skincare'
    const apiKey = c.env?.GSK_TOKEN || c.env?.gsk_token || ''
    const gKey   = c.env?.GOOGLE_PLACES_KEY || ''

    // autoGenSeo 호출: Google Places 정보 + 리뷰 + GPT로 완전히 고유한 텍스트 생성
    let description    = resolvedData.description || ''
    let whyChoose: string[] = resolvedData.whyChoose?.length ? resolvedData.whyChoose : []
    let metaDescription = resolvedData.metaDescription || ''
    let seoKeywords     = resolvedData.seoKeywords || ''

    const seoResult = await autoGenSeo({
      name:        engName,
      category:    cat,
      location:    loc,
      rating:      resolvedData.rating || 5,
      reviewCount: resolvedData.reviewCount || 0,
      placeId:     resolvedData.placeId || resolvedData.googlePlaceId || '',
      services:    resolvedData.services || [],
      reviews:     resolvedData.reviews  || [],
    }, apiKey, gKey)

    let seoTextVal = ''
    if (seoResult) {
      if (!description)    description    = seoResult.description
      if (!whyChoose.length) whyChoose    = seoResult.whyChoose
      if (!metaDescription) metaDescription = seoResult.metaDescription || ''
      if (!seoKeywords)    seoKeywords    = Array.isArray(seoResult.keywords) ? seoResult.keywords.join(', ') : ''
      seoTextVal = seoResult.seoText || ''
    }

    // fallback: GPT 실패 시 기본 템플릿
    if (!description)
      description = `${engName} is a highly rated ${cat} in ${loc}, Seoul. ` +
        `Rated ${resolvedData.rating || 5}/5 with ${resolvedData.reviewCount || 0}+ verified reviews. English consultations available. Book via WhatsApp with Seoul Beauty Trip.`
    if (!whyChoose.length) whyChoose = [
      `🌐 English-friendly service and easy WhatsApp booking for international visitors`,
      `⭐ Rated ${resolvedData.rating || 5}/5 with ${resolvedData.reviewCount || 0}+ verified reviews`,
      `👨‍⚕️ Expert team with experience serving international patients`,
      `📍 Conveniently located in ${loc}, Seoul — easily accessible from major transit hubs`,
      `💬 Dedicated support for overseas visitors from consultation to aftercare`
    ]
    if (!metaDescription)
      metaDescription = `${engName} ${loc} Seoul — Premium ${cat} for foreigners. English-speaking staff. Book via WhatsApp with Seoul Beauty Trip.`
    if (!seoKeywords)
      seoKeywords = `${engName} Seoul, ${engName} ${loc}, best ${cat} ${loc} Seoul, ${cat} Seoul English speaking`

    // fallback seo_text: GPT 실패 시 4섹션 sp-seo-h2 구조 자동 생성
    // (리뷰 섹션 제외 — DB reviews 필드에서 별도 렌더링됨)
    if (!seoTextVal) {
      const _catLabel: Record<string,string> = {
        clinic:'aesthetic & skin clinic', skincare:'skincare & dermatology clinic',
        hair:'hair salon', headspa:'head spa & beauty salon',
        tattoo:'permanent makeup & tattoo studio', makeup:'personal color & makeup studio', dental:'dental clinic'
      }
      const _cl = _catLabel[cat] || cat
      const _clTitle = _cl.charAt(0).toUpperCase()+_cl.slice(1)
      const _rt = String(resolvedData.rating || 5.0)
      const _rc = Number(resolvedData.reviewCount || 0).toLocaleString()
      const _locLabel = loc.includes('Seoul') ? loc : `${loc}, Seoul`
      const _whyItems = whyChoose.slice(0,5).map((w:string)=>`<li>${w}</li>`).join('')
      seoTextVal =
        `<h2 class="sp-seo-h2">${engName} — ${_clTitle} in ${_locLabel}</h2>`+
        `<p class="sp-seo-p">${engName} is a highly rated ${_cl} in ${_locLabel}, holding a <strong>${_rt}/5.0 rating</strong> from over <strong>${_rc} verified reviews</strong>. Consistently recommended by international visitors to Seoul in 2026 for its quality treatments and English-friendly service.</p>`+
        `<h2 class="sp-seo-h2">Why Travelers Choose ${engName}</h2>`+
        `<ul class="sp-seo-ul">${_whyItems}</ul>`+
        `<h2 class="sp-seo-h2">Treatments &amp; Services at ${engName}</h2>`+
        `<p class="sp-seo-p">${engName} provides ${_cl} treatments in ${_locLabel}, Seoul. From first consultation to aftercare, the team ensures every international guest feels comfortable and informed — with English support throughout.</p>`+
        `<h2 class="sp-seo-h2">How to Book ${engName} as a Foreign Visitor</h2>`+
        `<p class="sp-seo-p">Booking takes under 2 minutes — tap the WhatsApp button, describe your desired treatment, and our English-speaking team will confirm your appointment and explain pricing. Located in ${_locLabel}, easily accessible from major transit hubs. No Korean needed.</p>`
    }

    // ── STEP 7: photos 처리 — Schema.org thumbnailUrl 에러 방지 (https:// 절대 URL만 허용) ──
    const photos: string[] = sanitizePhotos(resolvedData.photos || [])
    const thumbnail = sanitizeThumb(resolvedData.thumbnail || '', photos)

    // ── STEP 8: reviews 처리 ──
    const reviews = resolvedData.reviews || []

    // ── STEP 9: DB에 업체 저장 (review_summary는 일단 null, 이후 백그라운드 채움) ──
    const shopId = 's' + Date.now()
    await sql`
      INSERT INTO shops (
        id, name, slug, category, location, address, hours,
        rating, review_count, thumbnail, photos,
        google_place_id, google_map_url, lat, lng,
        description, why_choose, meta_description, seo_keywords, seo_text,
        reviews, review_summary, active, created_at
      ) VALUES (
        ${shopId}, ${rawName}, ${slug}, ${cat},
        ${loc}, ${resolvedData.address || ''}, ${resolvedData.hours || ''},
        ${resolvedData.rating || 5.0}, ${resolvedData.reviewCount || 0},
        ${thumbnail}, ${JSON.stringify(photos)},
        ${resolvedData.placeId || ''}, ${gmapUrl}, ${resolvedData.lat || ''}, ${resolvedData.lng || ''},
        ${description}, ${JSON.stringify(whyChoose)}, ${metaDescription}, ${seoKeywords}, ${seoTextVal},
        ${JSON.stringify(reviews)}, null, true, NOW()
      )
    `

    // ── STEP 9.5: 백그라운드 작업 (응답 블로킹 없음) ──
    // DB 저장 완료 후 waitUntil로 비동기 실행 → 실패해도 등록 자체는 성공
    // ① 리뷰 요약: Gemini API는 항상 사용 가능 (apiKey 불필요)
    // ② 블로그 생성: apiKey(GSK_TOKEN) 있을 때만
    {
      const _bgSql = sql
      const _bgName = engName
      const _bgId = shopId
      const _bgKey = apiKey
      const _bgReviews = reviews
      const _bgCat = cat
      const _bgLoc = loc
      const _bgRating = resolvedData.rating || 5.0
      const _bgReviewCount = resolvedData.reviewCount || 0
      const _bgDesc = description
      const _bgWhyChoose = whyChoose
      const _bgSeoText = seoTextVal

      const _bgTask = (async () => {
        // ① 리뷰 요약 생성 — apiKey 없어도 Gemini로 항상 실행
        if (_bgReviews.length > 0) {
          try {
            const _bgGeminiKey = (c.env as any)?.GEMINI_API_KEY || GEMINI_API_KEY_DEFAULT
            const summary = await genReviewSummary(_bgName, _bgReviews, '', _bgGeminiKey)
            if (summary) {
              await _bgSql`UPDATE shops SET review_summary = ${JSON.stringify(summary)}::jsonb WHERE id = ${_bgId}`
            }
          } catch { /* 실패해도 무시 */ }
        }

        // ② 자동 블로그 생성 — apiKey 있을 때만
        if (_bgKey) {
          try {
            await autoGenShopBlog({
              id: _bgId, name: _bgName, category: _bgCat, location: _bgLoc,
              rating: _bgRating, reviewCount: _bgReviewCount,
              description: _bgDesc, reviews: _bgReviews,
              seoText: _bgSeoText, whyChoose: _bgWhyChoose
            }, _bgKey, _bgSql)
          } catch { /* 블로그 생성 실패해도 업체 등록에는 영향 없음 */ }
        }
      })()

      // Cloudflare Workers: waitUntil로 응답 후에도 백그라운드 실행 보장
      try { (c.executionCtx as any)?.waitUntil?.(_bgTask) } catch { /* non-CF 환경 무시 */ }
    }

    // ── STEP 10: 영상 URL이 있으면 같이 등록 ──
    let videoId = null
    if (videoUrl && videoUrl.trim()) {
      videoId = 'v' + Date.now()
      const thumb = videoUrl.includes('cloudinary.com')
        ? videoUrl.replace('/video/upload/', '/video/upload/so_0,w_600,h_1066,c_fill,q_auto/').replace(/\.mp4$/, '.jpg')
        : ''
      const today = new Date().toISOString().slice(0, 10)
      // eager 변환 URL 저장 (업로드 시 1회 변환 → 이후 크래딧 소모 없음)
      await sql`
        INSERT INTO videos (id, shop_id, title, description, video_url, thumbnail, tags, views, likes, created_at, video_url_low, video_url_mid, video_url_high, instagram_url)
        VALUES (${videoId}, ${shopId}, ${engName}, ${''}, ${videoUrl.trim()}, ${thumb}, ${'[]'}, 0, 0, ${today},
          ${videoUrlLow||null}, ${videoUrlMid||null}, ${videoUrlHigh||null}, ${instagramUrl||''})
      `
    }

    return c.json({
      success: true,
      shopId,
      shopName: rawName,
      slug,
      location: loc,
      videoId,
      url: `/shop/${slug}`
    })
  } catch(e: any) {
    return c.json({ error: e.message || '등록 중 오류가 발생했습니다' }, 500)
  }
})

// ══════════════════════════════════════════
// ── 방문자 행동 트래킹 API ──
// ══════════════════════════════════════════

// 봇 UA 감지 함수
function isBotUa(ua: string): boolean {
  if (!ua) return true
  const u = ua.toLowerCase()
  // 알려진 봇/크롤러 키워드
  if (/bot|crawl|spider|slurp|facebookexternalhit|pinterest|linkedinbot|twitterbot|whatsapp|telegram|slack|discord|semrush|ahrefs|mj12|dotbot|bingpreview|google-inspectiontool|chrome-lighthouse|headlesschrome|puppeteer|playwright|selenium/i.test(u)) return true
  // ⚠️ Chrome 버전 필터링 제거: Chrome 149는 2026년 6월 최신 안정 버전이므로 봇 아님
  // UA가 너무 짧거나 비정상
  if (ua.length < 20) return true
  return false
}

// 자사/내부 트래픽 제외 판단
// OWNER_IPS: 환경변수에 콤마 구분으로 설정 (예: "1.2.3.4,5.6.7.8")
function isInternalTraffic(ip: string, ref: string, page: string, env?: Env): boolean {
  // 1. 관리자 페이지 접근
  if (page && page.startsWith('/admin')) return true
  // 2. 자사 도메인 referrer (관리자/자체 테스트)
  if (ref && (
    ref.includes('seoulbeautytrip.vercel.app') ||
    ref.includes('localhost') ||
    ref.includes('127.0.0.1') ||
    ref.includes('.sandbox.gensparksite.com')
  )) return true
  // 3. 운영자 IP 차단 (하드코딩 + 환경변수 OWNER_IPS 콤마 구분 병합)
  const hardcodedOwnerIps = ['112.186.180.168']
  const ownerIps = (env as any)?.OWNER_IPS || (typeof process !== 'undefined' ? process.env.OWNER_IPS : '') || ''
  const ipList = [...hardcodedOwnerIps, ...ownerIps.split(',').map((s: string) => s.trim())].filter(Boolean)
  if (ip && ipList.includes(ip)) return true
  return false
}

// POST /api/track — 이벤트 수집
app.post('/api/track', async (c) => {
  try {
    const sql = getDb(c.env)
    const body: any = await c.req.json()
    const { session_id, visitor_id, event, page, target, value, shop_id, shop_name, duration, scroll_pct } = body
    if (!session_id || !visitor_id || !event) return c.json({ ok: false }, 400)

    const id = 've_' + Date.now() + '_' + Math.random().toString(36).slice(2,7)
    const ua = c.req.header('user-agent') || ''
    const ref = body.referrer || ''
    // 방문자 실제 IP (Cloudflare/Vercel 헤더 우선)
    const ip = c.req.header('cf-connecting-ip') || c.req.header('x-forwarded-for')?.split(',')[0].trim() || c.req.header('x-real-ip') || ''

    // 봇 UA 필터링
    if (isBotUa(ua)) return c.json({ ok: true, bot: true })
    // 내부/운영자 트래픽 필터링
    if (isInternalTraffic(ip, ref, page||'', c.env)) return c.json({ ok: true, internal: true })

    // 디바이스 감지
    const device = /mobile|android|iphone|ipad/i.test(ua) ? 'mobile' : 'desktop'

    // 이벤트 저장
    await sql`
      INSERT INTO visitor_events (id, session_id, visitor_id, event, page, target, value, shop_id, shop_name, duration, scroll_pct, referrer, ua, created_at)
      VALUES (${id}, ${session_id}, ${visitor_id}, ${event}, ${page||''}, ${target||''}, ${value||''}, ${shop_id||''}, ${shop_name||''}, ${duration||0}, ${scroll_pct||0}, ${ref}, ${ua.slice(0,200)}, NOW())
    `

    // 세션 upsert
    if (event === 'page_view') {
      await sql`
        INSERT INTO visitor_sessions (session_id, visitor_id, first_page, referrer, ua, device, started_at, last_active, page_count, event_count)
        VALUES (${session_id}, ${visitor_id}, ${page||''}, ${ref}, ${ua.slice(0,200)}, ${device}, NOW(), NOW(), 1, 1)
        ON CONFLICT (session_id) DO UPDATE SET
          last_active = NOW(),
          page_count = visitor_sessions.page_count + 1,
          event_count = visitor_sessions.event_count + 1
      `
    } else {
      await sql`
        UPDATE visitor_sessions SET
          last_active = NOW(),
          event_count = event_count + 1,
          wa_clicked = CASE WHEN ${event} = 'wa_click' THEN true ELSE wa_clicked END,
          max_scroll = CASE WHEN ${scroll_pct||0} > max_scroll THEN ${scroll_pct||0} ELSE max_scroll END
        WHERE session_id = ${session_id}
      `
    }

    return c.json({ ok: true })
  } catch(e: any) {
    return c.json({ ok: false, error: e.message }, 500)
  }
})

// GET /api/visitors — 방문자 세션 목록 (어드민)
app.get('/api/visitors', async (c) => {
  const auth = c.req.header('x-admin-token') || c.req.query('token') || ''
  const token = c.env?.GSK_TOKEN || c.env?.gsk_token || ''
  // token이 설정된 경우에만 검증 (미설정 환경에서는 어드민 페이지 자체가 보호됨)
  if (token && auth !== token) return c.json({ error: 'Unauthorized' }, 401)

  try {
    const sql = getDb(c.env)
    const limit = parseInt(c.req.query('limit') || '50')
    const offset = parseInt(c.req.query('offset') || '0')

    const sessions = await sql`
      SELECT
        vs.*,
        COUNT(ve.id) AS total_events,
        MAX(CASE WHEN ve.event = 'wa_click' THEN 1 ELSE 0 END)::int AS did_wa,
        MAX(CASE WHEN ve.event = 'video_play' THEN 1 ELSE 0 END)::int AS did_video,
        MAX(CASE WHEN ve.event = 'shop_view' THEN 1 ELSE 0 END)::int AS did_shop,
        ARRAY_AGG(DISTINCT ve.shop_name) FILTER (WHERE ve.shop_name != '') AS shops_viewed,
        EXTRACT(EPOCH FROM (vs.last_active - vs.started_at))::int AS duration_sec,
        -- 첫 이벤트의 referrer (vs.referrer가 없을 때 보완)
        COALESCE(
          NULLIF(vs.referrer, ''),
          (SELECT referrer FROM visitor_events
           WHERE session_id = vs.session_id AND referrer IS NOT NULL AND referrer != ''
             AND referrer NOT LIKE '%seoulbeautytrip%'
           ORDER BY created_at ASC LIMIT 1)
        ) AS first_referrer,
        -- 첫 진입 페이지 (vs.first_page 보완)
        COALESCE(
          NULLIF(vs.first_page, ''),
          (SELECT page FROM visitor_events WHERE session_id = vs.session_id ORDER BY created_at ASC LIMIT 1)
        ) AS entry_page
      FROM visitor_sessions vs
      LEFT JOIN visitor_events ve ON ve.session_id = vs.session_id
      WHERE
        -- 봇 UA 필터링 (Chrome 버전 기반 필터링 제거 - Chrome 149가 2026년 6월 최신버전)
        vs.ua NOT SIMILAR TO '%(bot|crawl|spider|headless|puppet|selenium|lighthouse)%'
        AND LENGTH(vs.ua) >= 20
      GROUP BY vs.session_id
      ORDER BY vs.started_at DESC
      LIMIT ${limit} OFFSET ${offset}
    `

    const total = await sql`
      SELECT COUNT(*) AS c FROM visitor_sessions
      WHERE
        ua NOT SIMILAR TO '%(bot|crawl|spider|headless|puppet|selenium|lighthouse)%'
        AND LENGTH(ua) >= 20
    `

    return c.json({ sessions, total: Number(total[0]?.c || 0) })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// GET /api/visitors/:sessionId — 세션별 이벤트 타임라인 (어드민)
app.get('/api/visitors/:sessionId', async (c) => {
  const auth = c.req.header('x-admin-token') || c.req.query('token') || ''
  const token = c.env?.GSK_TOKEN || c.env?.gsk_token || ''
  if (token && auth !== token) return c.json({ error: 'Unauthorized' }, 401)

  try {
    const sql = getDb(c.env)
    const sid = c.req.param('sessionId')
    // 이벤트 + 페이지별 체류시간 계산 포함
    const events = await sql`
      SELECT
        ve.*,
        EXTRACT(EPOCH FROM (
          LEAD(ve.created_at) OVER (PARTITION BY ve.session_id ORDER BY ve.created_at)
          - ve.created_at
        ))::int AS next_event_gap_sec
      FROM visitor_events ve
      WHERE ve.session_id = ${sid}
      ORDER BY ve.created_at ASC
    `
    const session = await sql`SELECT * FROM visitor_sessions WHERE session_id = ${sid}`
    // 페이지별 요약 (체류시간, 스크롤, 클릭수, shop_name JOIN)
    const pageSummary = await sql`
      SELECT
        ve.page,
        COUNT(*) FILTER (WHERE ve.event = 'page_view') AS views,
        MAX(ve.scroll_pct) AS max_scroll,
        COUNT(*) FILTER (WHERE ve.event = 'shop_click' OR ve.event = 'wa_click') AS clicks,
        MAX(ve.duration) AS stay_sec,
        MAX(sh.name) AS shop_name
      FROM visitor_events ve
      LEFT JOIN shops sh ON sh.slug = REGEXP_REPLACE(ve.page, '^/shop/', '')
                            AND ve.page LIKE '/shop/%'
      WHERE ve.session_id = ${sid} AND ve.page != ''
      GROUP BY ve.page
      ORDER BY MIN(ve.created_at)
    `
    // session camelCase 정규화
    const sessionNorm = session[0] ? {
      sessionId:   (session[0] as any).session_id   || (session[0] as any).sessionId   || '',
      visitorId:   (session[0] as any).visitor_id   || (session[0] as any).visitorId   || '',
      device:      (session[0] as any).device       || 'desktop',
      country:     (session[0] as any).country      || '',
      referrer:    (session[0] as any).referrer     || '',
      ua:          (session[0] as any).ua           || '',
      startedAt:   (session[0] as any).started_at   || (session[0] as any).startedAt   || '',
      lastActive:  (session[0] as any).last_active  || (session[0] as any).lastActive  || '',
      pageCount:   +((session[0] as any).page_count  || (session[0] as any).pageCount  || 0),
      maxScroll:   +((session[0] as any).max_scroll  || (session[0] as any).maxScroll  || 0),
      durationSec: +((session[0] as any).duration_sec || 0),
      waClicked:   !!((session[0] as any).wa_clicked || (session[0] as any).waClicked),
    } : null
    // pageSummary camelCase 정규화
    const pageSummaryNorm = (pageSummary as any[]).map(p => ({
      page:      p.page      || '/',
      views:     +(p.views   || 0),
      maxScroll: +(p.max_scroll || p.maxScroll || 0),
      clicks:    +(p.clicks  || 0),
      staySec:   +(p.stay_sec || p.staySec || 0),
      shopName:  p.shop_name || p.shopName || null,
    }))
    return c.json({ session: sessionNorm, events, pageSummary: pageSummaryNorm })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// GET /api/visitors-live — 실시간 접속자 (최근 3분 내 active 세션)
app.get('/api/visitors-live', async (c) => {
  const auth = c.req.header('x-admin-token') || c.req.query('token') || ''
  const token = c.env?.GSK_TOKEN || c.env?.gsk_token || ''
  if (token && auth !== token) return c.json({ error: 'Unauthorized' }, 401)

  try {
    const sql = getDb(c.env)

    // 최근 3분 이내 last_active인 세션 = 실시간 접속자 (봇 제외)
    const liveSessions = await sql`
      SELECT vs.session_id, vs.visitor_id, vs.device,
             (SELECT page FROM visitor_events WHERE session_id=vs.session_id ORDER BY created_at DESC LIMIT 1) AS current_page
      FROM visitor_sessions vs
      WHERE last_active >= NOW() - INTERVAL '3 minutes'
        AND vs.ua NOT SIMILAR TO '%(bot|crawl|spider|headless|puppet|selenium|lighthouse)%'
        AND LENGTH(vs.ua) >= 20
      ORDER BY last_active DESC
    `

    // /shop/slug → 업체명 변환 헬퍼: slug 목록 수집 후 한 번에 JOIN
    const slugSet = new Set<string>()
    for (const s of liveSessions as any[]) {
      const pg: string = s.current_page || ''
      const m = pg.match(/^\/shop\/([^/?#]+)/)
      if (m) slugSet.add(m[1])
    }

    // 최근 나가기 이벤트 (page_exit, 최근 10개) — shops JOIN으로 업체명 포함
    const recentExits = await sql`
      SELECT ve.id, ve.page, ve.duration, ve.created_at,
             vs.device,
             sh.name AS shop_name
      FROM visitor_events ve
      LEFT JOIN visitor_sessions vs ON vs.session_id = ve.session_id
      LEFT JOIN shops sh ON sh.slug = REGEXP_REPLACE(ve.page, '^/shop/', '')
                            AND ve.page LIKE '/shop/%'
      WHERE ve.event = 'page_exit'
      ORDER BY ve.created_at DESC
      LIMIT 10
    `

    // slug → 업체명 맵 (실시간 접속자용)
    let slugNameMap: Record<string, string> = {}
    if (slugSet.size > 0) {
      const slugArr = Array.from(slugSet)
      const shopRows = await sql`SELECT slug, name FROM shops WHERE slug = ANY(${slugArr}::text[])`
      for (const r of shopRows as any[]) slugNameMap[r.slug] = r.name
    }

    // 현재 보고 있는 페이지별 집계 (업체명 포함)
    const pageMap: Record<string, { count: number; shopName?: string }> = {}
    for (const s of liveSessions as any[]) {
      const pg = s.current_page || '/'
      if (!pageMap[pg]) {
        const m = pg.match(/^\/shop\/([^/?#]+)/)
        const shopName = m ? slugNameMap[m[1]] : undefined
        pageMap[pg] = { count: 0, shopName }
      }
      pageMap[pg].count++
    }
    const activePages = Object.entries(pageMap)
      .map(([page, v]) => ({ page, count: v.count, shopName: v.shopName }))
      .sort((a, b) => b.count - a.count)

    const lastExit = (recentExits as any[])[0]
    return c.json({
      activeCount: liveSessions.length,
      activePages,
      lastExitPage:   lastExit?.page || '',
      lastExitDevice: lastExit?.device || '',
      recentExits
    })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// GET /api/visitors-stats — 요약 통계 (어드민)
app.get('/api/visitors-stats', async (c) => {
  const auth = c.req.header('x-admin-token') || c.req.query('token') || ''
  const token = c.env?.GSK_TOKEN || c.env?.gsk_token || ''
  if (token && auth !== token) return c.json({ error: 'Unauthorized' }, 401)

  try {
    const sql = getDb(c.env)
    const days = parseInt(c.req.query('days') || '7')

    const [totalsRaw, byDeviceRaw, byPageRaw, topShopsRaw, hourlyRaw, waFunnelRaw, bySourceRaw, byLangRaw, byBrowserRaw] = await Promise.all([
      sql`SELECT
        COUNT(DISTINCT visitor_id)::int AS unique_visitors,
        COUNT(*)::int AS total_sessions,
        ROUND(AVG(EXTRACT(EPOCH FROM (last_active - started_at)))::numeric, 0)::int AS avg_duration_sec,
        SUM(CASE WHEN wa_clicked THEN 1 ELSE 0 END)::int AS wa_clicks,
        ROUND(AVG(max_scroll)::numeric, 0)::int AS avg_scroll,
        ROUND(AVG(page_count)::numeric, 1)::float AS avg_pages
        FROM visitor_sessions
        WHERE started_at > NOW() - (${days} || ' days')::interval`,
      sql`SELECT device, COUNT(*)::int AS cnt FROM visitor_sessions
        WHERE started_at > NOW() - (${days} || ' days')::interval
        GROUP BY device ORDER BY cnt DESC`,
      sql`SELECT page, COUNT(*)::int AS cnt FROM visitor_events
        WHERE event = 'page_view' AND created_at > NOW() - (${days} || ' days')::interval
        GROUP BY page ORDER BY cnt DESC LIMIT 10`,
      sql`SELECT sh.name AS shop_name,
        COUNT(DISTINCT ve.session_id)::int AS views,
        SUM(CASE WHEN ve.event = 'wa_click' THEN 1 ELSE 0 END)::int AS wa
        FROM visitor_events ve
        JOIN shops sh ON sh.slug = REGEXP_REPLACE(ve.page, '^/shop/', '')
                         AND ve.page LIKE '/shop/%'
        WHERE ve.event IN ('page_view','page_exit','shop_view','wa_click')
          AND ve.created_at > NOW() - (${days} || ' days')::interval
        GROUP BY sh.name ORDER BY views DESC LIMIT 8`,
      sql`SELECT EXTRACT(HOUR FROM created_at)::int AS hour, COUNT(DISTINCT session_id)::int AS cnt
        FROM visitor_events WHERE event = 'page_view'
        AND created_at > NOW() - (${days} || ' days')::interval
        GROUP BY hour ORDER BY hour`,
      sql`SELECT
        COUNT(DISTINCT session_id)::int AS total_sessions,
        SUM(CASE WHEN did_video > 0 THEN 1 ELSE 0 END)::int AS watched_video,
        SUM(CASE WHEN did_shop > 0 THEN 1 ELSE 0 END)::int AS viewed_shop,
        SUM(CASE WHEN wa_clicked THEN 1 ELSE 0 END)::int AS clicked_wa
        FROM (
          SELECT vs.session_id, vs.wa_clicked,
            MAX(CASE WHEN ve.event = 'video_play' THEN 1 ELSE 0 END) AS did_video,
            MAX(CASE WHEN ve.event = 'shop_view' THEN 1 ELSE 0 END) AS did_shop
          FROM visitor_sessions vs
          LEFT JOIN visitor_events ve ON ve.session_id = vs.session_id
          WHERE vs.started_at > NOW() - (${days} || ' days')::interval
          GROUP BY vs.session_id, vs.wa_clicked
        ) t`,
      // ── 유입 소스 분포 ──
      sql`SELECT
        CASE
          WHEN referrer ILIKE '%instagram%' OR referrer ILIKE '%l.instagram%' THEN 'Instagram'
          WHEN referrer ILIKE '%facebook%' OR referrer ILIKE '%fb.com%' OR referrer ILIKE '%fb_iab%' OR referrer ILIKE '%fbclid%' THEN 'Facebook'
          WHEN referrer ILIKE '%google%' THEN 'Google'
          WHEN referrer ILIKE '%tiktok%' THEN 'TikTok'
          WHEN referrer ILIKE '%twitter%' OR referrer ILIKE '%t.co%' THEN 'Twitter/X'
          WHEN referrer ILIKE '%youtube%' THEN 'YouTube'
          WHEN referrer ILIKE '%pinterest%' THEN 'Pinterest'
          WHEN referrer IS NULL OR referrer = '' THEN 'Direct'
          ELSE 'Other'
        END AS source,
        COUNT(*)::int AS cnt
        FROM visitor_sessions
        WHERE started_at > NOW() - (${days} || ' days')::interval
        GROUP BY source ORDER BY cnt DESC`,
      // ── 언어/국가 분포 (UA 파싱) ──
      sql`SELECT
        CASE
          WHEN ua ILIKE '%en_US%' OR ua ILIKE '%en-US%' THEN 'en-US'
          WHEN ua ILIKE '%en_GB%' OR ua ILIKE '%en-GB%' THEN 'en-GB'
          WHEN ua ILIKE '%en_AU%' OR ua ILIKE '%en-AU%' THEN 'en-AU'
          WHEN ua ILIKE '%en_CA%' OR ua ILIKE '%en-CA%' THEN 'en-CA'
          WHEN ua ILIKE '%en_SG%' OR ua ILIKE '%en-SG%' THEN 'en-SG'
          WHEN ua ILIKE '%en_PH%' OR ua ILIKE '%en-PH%' THEN 'en-PH'
          WHEN ua ILIKE '%zh_CN%' OR ua ILIKE '%zh-CN%' THEN 'zh-CN'
          WHEN ua ILIKE '%zh_TW%' OR ua ILIKE '%zh-TW%' THEN 'zh-TW'
          WHEN ua ILIKE '%ja_JP%' OR ua ILIKE '%ja-JP%' OR ua ILIKE '% ja%' THEN 'ja'
          WHEN ua ILIKE '%ko_KR%' OR ua ILIKE '%ko-KR%' THEN 'ko-KR'
          WHEN ua ILIKE '%th_%' OR ua ILIKE '%th-%' THEN 'th'
          WHEN ua ILIKE '%ms_%' OR ua ILIKE '%ms-%' THEN 'ms'
          WHEN ua ILIKE '%id_%' OR ua ILIKE '%id-%' THEN 'id'
          WHEN ua ILIKE '%fr_%' OR ua ILIKE '%fr-%' THEN 'fr'
          WHEN ua ILIKE '%de_%' OR ua ILIKE '%de-%' THEN 'de'
          WHEN (ua ILIKE '%ko%' AND ua NOT ILIKE '%en%') THEN 'ko'
          ELSE 'other'
        END AS lang,
        COUNT(*)::int AS cnt
        FROM visitor_sessions
        WHERE started_at > NOW() - (${days} || ' days')::interval
        GROUP BY lang ORDER BY cnt DESC`,
      // ── 브라우저/OS 분포 ──
      sql`SELECT
        CASE
          WHEN ua ILIKE '%Instagram%' THEN 'Instagram IAB'
          WHEN ua ILIKE '%FBAV%' OR ua ILIKE '%FB_IAB%' THEN 'Facebook IAB'
          WHEN ua ILIKE '%TikTok%' THEN 'TikTok IAB'
          WHEN ua ILIKE '%SamsungBrowser%' THEN 'Samsung Browser'
          WHEN ua ILIKE '%EdgA%' OR ua ILIKE '%EdgW%' THEN 'Edge Mobile'
          WHEN ua ILIKE '%OPR%' OR ua ILIKE '%OPiOS%' THEN 'Opera'
          WHEN ua ILIKE '%CriOS%' THEN 'Chrome iOS'
          WHEN ua ILIKE '%FxiOS%' THEN 'Firefox iOS'
          WHEN ua ILIKE '%Chrome%' AND ua ILIKE '%Mobile%' THEN 'Chrome Mobile'
          WHEN ua ILIKE '%Chrome%' THEN 'Chrome'
          WHEN ua ILIKE '%Safari%' AND ua ILIKE '%Mobile%' THEN 'Safari Mobile'
          WHEN ua ILIKE '%Safari%' THEN 'Safari'
          WHEN ua ILIKE '%Firefox%' THEN 'Firefox'
          ELSE 'Other'
        END AS browser,
        COUNT(*)::int AS cnt
        FROM visitor_sessions
        WHERE started_at > NOW() - (${days} || ' days')::interval
        GROUP BY browser ORDER BY cnt DESC LIMIT 8`
    ])

    // snake_case → camelCase 정규화
    const t = totalsRaw[0] as any || {}
    const totalsNorm = {
      uniqueVisitors:   +(t.unique_visitors   ?? t.uniqueVisitors   ?? 0),
      sessions:         +(t.total_sessions    ?? t.sessions         ?? 0),
      avgDuration:      +(t.avg_duration_sec  ?? t.avgDuration      ?? 0),
      waClicks:         +(t.wa_clicks         ?? t.waClicks         ?? 0),
      avgScroll:        +(t.avg_scroll        ?? t.avgScroll        ?? 0),
      pagesPerSession:  +(t.avg_pages         ?? t.pagesPerSession  ?? 0),
    }

    const byDevice = (byDeviceRaw as any[]).map(r => ({
      device: r.device,
      count:  +(r.cnt ?? r.count ?? 0),
    }))

    const byPage = (byPageRaw as any[]).map(r => ({
      page:  r.page,
      count: +(r.cnt ?? r.count ?? 0),
    }))

    const topShops = (topShopsRaw as any[]).map(r => ({
      shopName: r.shop_name ?? r.shopName ?? '',
      views:    +(r.views ?? 0),
      wa:       +(r.wa ?? 0),
    }))

    const hourly = (hourlyRaw as any[]).map(r => ({
      hour:  +(r.hour ?? 0),
      count: +(r.cnt ?? r.sessions ?? r.count ?? 0),
    }))

    const wf = waFunnelRaw[0] as any || {}
    const waFunnel = {
      visits:       +(wf.total_sessions ?? wf.visits       ?? 0),
      videoWatched: +(wf.watched_video  ?? wf.videoWatched ?? 0),
      shopViews:    +(wf.viewed_shop    ?? wf.shopViews    ?? 0),
      waClicks:     +(wf.clicked_wa     ?? wf.waClicks     ?? 0),
    }

    const bySource = (bySourceRaw as any[]).map(r => ({ source: r.source, count: +(r.cnt ?? 0) }))
    const byLang   = (byLangRaw   as any[]).map(r => ({ lang:   r.lang,   count: +(r.cnt ?? 0) }))
    const byBrowser= (byBrowserRaw as any[]).map(r => ({ browser: r.browser, count: +(r.cnt ?? 0) }))

    return c.json({ totals: totalsNorm, byDevice, byPage, topShops, hourly, waFunnel, bySource, byLang, byBrowser })
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ══════════════════════════════════════════
// ── 일괄 SEO 재생성 API ──
// ── POST /api/admin/reset-video-views — 영상 조회수 초기화 ──
app.post('/api/admin/reset-video-views', async (c) => {
  const sql = getDb(c.env)
  await sql`UPDATE videos SET views=0`
  await sql`DELETE FROM video_views_log`
  const [cnt] = await sql`SELECT COUNT(*) as c FROM videos`
  return c.json({ ok: true, message: `Reset views=0 for ${cnt.c} videos, cleared view log` })
})

// ── POST /api/admin/fix-video-thumbnails ──
// thumbnail이 비어있는 영상들에 Cloudinary so_0 자동 썸네일을 DB에 일괄 저장
app.post('/api/admin/fix-video-thumbnails', async (c) => {
  const sql = getDb(c.env)
  const rows = await sql`SELECT id, video_url FROM videos WHERE (thumbnail IS NULL OR thumbnail='') AND video_url IS NOT NULL AND video_url != ''` as any[]
  let fixed = 0
  for (const r of rows) {
    const vUrl = r.video_url || ''
    if (!vUrl.includes('cloudinary.com')) continue
    const thumb = vUrl
      .replace('/video/upload/', '/video/upload/so_0,w_600,h_1066,c_fill,q_auto/')
      .replace(/\.mp4$/, '.jpg')
    await sql`UPDATE videos SET thumbnail=${thumb} WHERE id=${r.id}`
    fixed++
  }
  return c.json({ ok: true, fixed, total: rows.length })
})

// ── POST /api/admin/migrate-video-urls ──
// 기존 영상 중 video_url_low/mid/high가 없는 영상에 대해
// Cloudinary URL 파라미터 변환을 적용한 URL을 DB에 저장
// (크래딧 절약: on-the-fly 대신 DB에 미리 저장된 URL 사용)
// ⚠️  이 엔드포인트는 Cloudinary 크래딧을 1회 소모 (마이그레이션 시에만 호출)
// 단, 이후 재생 시에는 DB URL 그대로 사용 → 추가 크래딧 없음
app.post('/api/admin/migrate-video-urls', async (c) => {
  const sql = getDb(c.env)
  // force=true: fl_progressive 미적용 영상 포함 전체 재변환
  const body = await c.req.json().catch(() => ({})) as any
  const force = body?.force === true

  const rows = await sql`
    SELECT id, video_url, video_url_low FROM videos
    WHERE video_url IS NOT NULL AND video_url != ''
      AND video_url LIKE '%res.cloudinary.com%'
  ` as any[]

  // force=false: fl_progressive 미적용이거나 아직 없는 영상만 처리
  const targets = force
    ? rows
    : rows.filter((r: any) => !r.video_url_low || !r.video_url_low.includes('fl_progressive'))

  let migrated = 0
  for (const r of targets) {
    const base = r.video_url as string
    const makeCldUrl = (transform: string) =>
      base.replace('/video/upload/', '/video/upload/' + transform + '/')

    // fl_progressive:steep: moov atom을 파일 맨 앞으로 이동 → 첫 바이트부터 재생 가능
    // 비트레이트: 300k(low)/600k(mid)/1200k(high) - 릴스 수준 즉시 재생 달성
    const urlLow  = makeCldUrl('fl_progressive:steep,q_auto:low,w_360,h_640,c_fill,vc_h264,br_300k,f_mp4')
    const urlMid  = makeCldUrl('fl_progressive:steep,q_auto:good,w_480,h_854,c_fill,vc_h264,br_600k,f_mp4')
    const urlHigh = makeCldUrl('fl_progressive:steep,q_auto:good,w_720,h_1280,c_fill,vc_h264,br_1200k,f_mp4')

    await sql`UPDATE videos SET video_url_low=${urlLow}, video_url_mid=${urlMid}, video_url_high=${urlHigh} WHERE id=${r.id}`
    migrated++
  }
  return c.json({ ok: true, migrated, total: targets.length,
    note: force
      ? '전체 강제 재마이그레이션 완료 (fl_progressive:steep + 비트레이트 최적화)'
      : `fl_progressive 미적용 ${migrated}개 영상 마이그레이션 완료` })
})

// POST /api/admin/fix-slugs
// → 모든 업체 slug를 name+location 기반으로 재생성 (숫자 suffix → 지역명 suffix)
// ══════════════════════════════════════════
app.post('/api/admin/fix-slugs', async (c) => {
  const sql = getDb(c.env)
  const rows = await sql`SELECT id, name, location, slug FROM shops ORDER BY created_at ASC`
  const results: {id:string, name:string, old:string, new:string}[] = []
  const clean = (s: string) => s.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '')

  for (const row of rows) {
    const base = clean(row.name || '') || 'shop'
    // 지역명: 첫 파트만 사용
    const parts = (row.location || '').split(',').map((p: string) => p.trim()).filter(Boolean)
    const area = clean(parts[0] || '')

    // ✅ 핵심: base(name) 또는 기존 slug 어느 쪽에도 area가 없을 때만 추가
    // - base에 포함: "fleur-jardin-myeongdong" → name clean 결과에 myeongdong 있음 → 추가 안 함
    // - slug에 포함: 기존 slug가 이미 올바른 경우도 재추가 방지
    const baseHasArea = area && base.includes(area)
    const slugHasArea = area && row.slug.includes(area)
    const candidate = (area && !baseHasArea && !slugHasArea) ? `${base}-${area}` : base

    // 자기 자신 제외 중복 확인
    const conflict = await sql`SELECT slug FROM shops WHERE slug=${candidate} AND id!=${row.id}`
    let newSlug = candidate
    if (conflict.length > 0) {
      for (let n = 2; n <= 99; n++) {
        const s = `${candidate}-${n}`
        const c2 = await sql`SELECT slug FROM shops WHERE slug=${s} AND id!=${row.id}`
        if (!c2.length) { newSlug = s; break }
      }
    }
    if (newSlug !== row.slug) {
      await sql`UPDATE shops SET slug=${newSlug} WHERE id=${row.id}`
      results.push({ id: row.id, name: row.name, old: row.slug, new: newSlug })
    }
  }
  return c.json({ ok: true, updated: results.length, results })
})

// POST /api/admin/regenerate-seo-all
// → 모든 활성 업체 순회, description/metaDescription/seoKeywords 없는 것 자동 생성
// ══════════════════════════════════════════
app.post('/api/admin/regenerate-seo-all', async (c) => {
  const sql = getDb(c.env)
  const apiKey = c.env?.GSK_TOKEN || c.env?.gsk_token || c.env?.GENSPARK_TOKEN || c.env?.genspark_token || ''
  if (!apiKey) return c.json({ error: 'API key not configured' }, 500)

  // 쿼리파라미터: force=true 이면 이미 있는 것도 재생성
  const force = c.req.query('force') === 'true'

  // no_h2=true: seoText에 h2 태그 없는 업체만 재생성 (H2 없는 34개 업체 타겟)
  const noH2Only = c.req.query('no_h2') === 'true'

  let rows: any[] = []
  try {
    rows = force
      ? await sql`SELECT * FROM shops WHERE active=true ORDER BY created_at ASC`
      : noH2Only
      ? await sql`SELECT * FROM shops WHERE active=true AND (seo_text IS NULL OR seo_text='' OR seo_text NOT LIKE '%<h2%') ORDER BY created_at ASC`
      : await sql`SELECT * FROM shops WHERE active=true AND (description IS NULL OR description='' OR meta_description IS NULL OR meta_description='') ORDER BY created_at ASC`
  } catch(e: any) {
    return c.json({ error: e.message }, 500)
  }

  const results: {id:string, name:string, status:string}[] = []

  for (const row of rows) {
    const shop = rowToShop(row)
    try {
      const gKey = getGoogleKey(c.env)
      const seo = await autoGenSeo({
        name:        shop.name,
        category:    shop.category,
        location:    shop.location,
        services:    shop.services,
        priceRange:  shop.priceRange,
        rating:      shop.rating,
        reviewCount: shop.reviewCount,
        placeId:     (shop as any).googlePlaceId || '',
        reviews:     (shop as any).reviews || [],
      }, apiKey, gKey)
      if (!seo) { results.push({ id: shop.id, name: shop.name, status: 'skipped (api fail)' }); continue }

      await sql`UPDATE shops SET
        description      = ${seo.description   || shop.description},
        meta_description = ${seo.metaDescription || ''},
        seo_keywords     = ${Array.isArray(seo.keywords) ? seo.keywords.join(', ') : ''},
        why_choose       = ${JSON.stringify(Array.isArray(seo.whyChoose) ? seo.whyChoose : [])},
        seo_text         = ${seo.seoText || ''}
        WHERE id = ${shop.id}`
      results.push({ id: shop.id, name: shop.name, status: 'updated' })
    } catch(e: any) {
      results.push({ id: shop.id, name: shop.name, status: 'error: ' + e.message })
    }
    // Rate limit 방지: 각 업체 사이 0.5초 대기
    await new Promise(r => setTimeout(r, 500))
  }

  return c.json({ total: rows.length, results })
})

