// 블로그 slug 생성
function makeBlogSlug(title: string): string {
  return title.toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 80)
    .replace(/^-|-$/g, '')
}

// 업체 등록 시 자동 블로그 글 생성 헬퍼
// 크레딧 최소화: haiku 모델 + 업체 DB 데이터(리뷰/SEO텍스트/설명)만 활용 → 외부 검색 API 미호출
async function autoGenShopBlog(shop: {
  id: string, name: string, category: string, location: string,
  rating: number, reviewCount: number, description: string,
  reviews: any[], seoText: string, whyChoose: string[]
}, apiKey: string, sql: any): Promise<void> {
  if (!apiKey) return

  const area = (shop.location || 'Seoul').split(',')[0].trim()
  const catLabel: Record<string,string> = {
    clinic:'Skin Clinic', hair:'Hair Salon', headspa:'Head Spa',
    skincare:'Skincare Clinic', makeup:'Personal Color Studio',
    tattoo:'Eyebrow Tattoo Studio', dental:'Dental Clinic'
  }
  const cat = catLabel[shop.category] || shop.category

  // 이미 같은 shop_id로 블로그 글 있으면 스킵 (중복 방지)
  const existing = await sql`SELECT id FROM blog_posts WHERE shop_id=${shop.id} LIMIT 1`.catch(() => [])
  if (existing.length > 0) return

  // 리뷰 스니펫 (최대 3개, 각 150자) — 실제 고객 목소리 반영
  const reviewSnippets = (shop.reviews || [])
    .slice(0, 3)
    .map((r: any) => (r.text || '').trim().slice(0, 150))
    .filter(Boolean)
    .join('\n- ')

  // SEO텍스트에서 핵심 내용 추출 (태그 제거, 300자)
  const seoContext = (shop.seoText || '').replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim().slice(0, 300)

  // 카테고리별 title 다양화 — Review 일색 탈피
  const titleTemplates: Record<string, string[]> = {
    headspa: [
      `${shop.name} Head Spa Review 2026: Worth It for Foreigners in ${area}?`,
      `I Tried ${shop.name} in ${area} — Honest Head Spa Guide for Tourists (2026)`,
      `${shop.name} ${area}: Best Head Spa for Foreigners? (2026 Guide)`,
    ],
    hair: [
      `${shop.name} Hair Salon in ${area}: Honest Guide for Foreigners (2026)`,
      `Getting My Hair Done at ${shop.name} in ${area} — Tourist's Honest Take`,
      `${shop.name} ${area}: Is It the Best Hair Salon for Foreigners in Seoul? (2026)`,
    ],
    nail: [
      `${shop.name} Nail Studio in ${area}: Worth Visiting as a Tourist? (2026)`,
      `K-Beauty Nails at ${shop.name} in ${area} — What Foreigners Need to Know (2026)`,
      `${shop.name} ${area}: Best Nail Art Studio for Tourists in Seoul? (2026)`,
    ],
    clinic: [
      `${shop.name} Skin Clinic in ${area}: Honest Guide for Foreigners (2026)`,
      `Is ${shop.name} in ${area} Worth It for Foreign Visitors? (2026)`,
      `${shop.name} ${area}: What Tourists Should Know Before Booking (2026)`,
    ],
    skincare: [
      `${shop.name} in ${area}: Honest Skincare Guide for Foreigners (2026)`,
      `${shop.name} ${area} Review 2026: Best Skincare Clinic for Tourists?`,
      `I Visited ${shop.name} in ${area} — Here's What Foreign Visitors Should Know`,
    ],
    spa: [
      `${shop.name} Spa in ${area}: Is It Worth It for Tourists? (2026)`,
      `Relaxing at ${shop.name} in ${area} — Honest Guide for Foreign Visitors (2026)`,
    ],
    tattoo: [
      `${shop.name} in ${area}: Eyebrow Tattoo Guide for Foreigners (2026)`,
      `Getting Eyebrow Tattoo at ${shop.name} in ${area} — Honest Tourist Guide (2026)`,
    ],
    dental: [
      `${shop.name} Dental Clinic in ${area}: Is It Worth It for Foreigners? (2026)`,
      `${shop.name} in ${area}: Honest Dental Guide for Foreign Visitors (2026)`,
    ],
  }
  const defaultTitles = [
    `${shop.name} Review 2026: Honest Guide for Foreigners in ${area}`,
    `${shop.name} in ${area}: Worth It for Foreign Visitors? (2026)`,
    `I Visited ${shop.name} in ${area} — Here's My Honest Take (2026)`,
  ]
  const titlePool = titleTemplates[cat.toLowerCase()] || titleTemplates[shop.category?.toLowerCase() || ''] || defaultTitles
  const title = titlePool[Math.floor(Math.random() * titlePool.length)]

  const prompt = `You are a Seoul travel writer who has personally visited many K-beauty clinics. Write like a real person sharing their honest experience — not a brochure or AI.

Write a blog post about "${shop.name}", a ${cat} in ${area}, Seoul for seoulbeautytrip.com.

REAL DATA (use exactly — do NOT invent numbers or reviews):
- Rating: ${shop.rating}/5 from ${shop.reviewCount}+ Google reviews
- About: ${shop.description || seoContext || 'Premium ' + cat + ' in ' + area}
- What regulars love: ${(shop.whyChoose || []).slice(0,3).join(' | ')}
${reviewSnippets ? `- Actual customer quotes (use these verbatim in blockquotes):\n  "${reviewSnippets.replace(/\n- /g, '"\n  "')}"` : ''}

Write HTML (900-1100 words) with this structure:
<h2>My Honest Take on ${shop.name} (${area}, Seoul)</h2>
<p>[2-3 sentence hook — why someone would search for this place. Be specific to ${area} and the type of visitor.]</p>
<p>[Context paragraph — what kind of place this is, who it's best for]</p>
<h2>What Real Visitors Say</h2>
<p>[Intro to reviews — 1 sentence]</p>
[Insert 2-3 blockquotes using this EXACT style (dark-theme safe):
<blockquote style="border-left:4px solid #FF4D8D;padding:14px 18px;margin:16px 0;background:rgba(255,77,141,0.06);border-radius:0 8px 8px 0;">
<p style="font-style:italic;color:rgba(255,255,255,0.85);margin:0 0 6px 0;">"[exact review text]"</p>
</blockquote>]
<p>[Your interpretation — what these reviews tell us about the experience]</p>
<h2>Treatments & What's on the Menu</h2>
<p>[List main treatments naturally in prose, not bullets. Mention any standout services.]</p>
<h2>Pricing Reality Check</h2>
<p>[Honest price framing — Korea is X% cheaper than [comparison country], don't give fake numbers, do say "confirm at booking"]</p>
<h2>The Foreigner Experience — Language, Booking, What to Know</h2>
<p>[English availability, WhatsApp booking via Seoul Beauty Trip, any practical tips]</p>
<ul style="color:rgba(255,255,255,0.8);padding-left:20px;">
<li>[Tip 1 — specific and practical]</li>
<li>[Tip 2]</li>
<li>[Tip 3 — e.g. location tip for ${area}]</li>
</ul>
<h2>Getting to ${shop.name}</h2>
<p>[Location in ${area} — nearest station, landmark, practical detail]</p>
<h2>FAQ</h2>
<h3>Is ${shop.name} worth it for foreigners?</h3><p>[Direct answer]</p>
<h3>Do they speak English at ${shop.name}?</h3><p>[Answer]</p>
<h3>How do I book ${shop.name} as a tourist?</h3><p>[WhatsApp via Seoul Beauty Trip answer]</p>

RULES:
- HTML only, no markdown
- All inline styles must use rgba() or hex — NO hsl() or named colors like "white"/"gray"
- Blockquotes MUST use the dark-theme style shown above (rgba background, not #f9fafb)
- Write like a real traveller — specific details beat generic praise
- Cite the ${shop.rating}/5 rating and ${shop.reviewCount}+ reviews naturally
- NO photo tags, figure tags, or image references — photos are handled separately
- No fake prices, no invented facts

After HTML add ---JSON---
{"metaDescription":"[max 155 chars, include '${shop.name}' and '${area}']","excerpt":"[2 sentence hook for the blog card]","tags":["${shop.name} review","${area} ${cat}","${cat} Seoul foreigners","Seoul beauty 2026","${shop.name} worth it"]}`

  try {
    const res = await fetch('https://www.genspark.ai/api/llm_proxy/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({
        model: 'claude-haiku-4-5', // 크레딧 최소: haiku 사용
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 2500,
        temperature: 0.6
      })
    })
    if (!res.ok) return
    const data: any = await res.json()
    const raw = data.choices?.[0]?.message?.content || ''
    if (!raw) return

    const parts = raw.split('---JSON---')
    let htmlContent = parts[0].trim()
    if (!htmlContent || htmlContent.length < 200) return

    // 혹시 AI가 생성한 <figure>/<img> 태그 제거 (사진은 블로그 상세 페이지에서 갤러리로 렌더링)
    htmlContent = htmlContent
      .replace(/<figure[\s\S]*?<\/figure>/gi, '')
      .replace(/\{\{PHOTO_\d\}\}/g, '')

    let metaDescription = '', excerpt = '', tags: string[] = []
    if (parts[1]) {
      try {
        const m = JSON.parse(parts[1].trim().replace(/```json|```/g,'').trim())
        metaDescription = m.metaDescription || ''
        excerpt = m.excerpt || ''
        tags = Array.isArray(m.tags) ? m.tags : []
      } catch {}
    }

    const blogId = 'b' + Date.now() + Math.random().toString(36).slice(2,5)
    const slug = makeBlogSlug(title)
    const now = new Date().toISOString().slice(0,10)

    // slug 중복 체크
    const dupCheck = await sql`SELECT id FROM blog_posts WHERE slug=${slug} LIMIT 1`.catch(() => [])
    if (dupCheck.length > 0) return

    // cover_image: 썸네일을 OG 이미지로도 사용
    const coverImg = (await sql`SELECT thumbnail FROM shops WHERE id=${shop.id} LIMIT 1`.catch(() => []))?.[0]?.thumbnail || ''

    await sql`INSERT INTO blog_posts
      (id, slug, title, content, excerpt, meta_description, category, area, tags, cover_image, status, views, shop_id, created_at, updated_at)
      VALUES (
        ${blogId}, ${slug}, ${title}, ${htmlContent}, ${excerpt}, ${metaDescription},
        ${shop.category}, ${area}, ${JSON.stringify(tags)}, ${coverImg}, 'published', 0, ${shop.id}, ${now}, ${now}
      )`
  } catch { /* 실패해도 무시 */ }
}

// AI 블로그 본문 생성
async function autoGenBlog(params: {
  title: string, category: string, area: string, keywords: string[]
}, apiKey: string): Promise<{ content: string, excerpt: string, metaDescription: string, tags: string[] } | null> {
  if (!apiKey) return null
  const { title, category, area, keywords } = params
  const prompt = `You are an expert travel & beauty writer creating an SEO-optimized blog post for seoulbeautytrip.com — a K-beauty booking platform for foreign visitors in Seoul.

Write a comprehensive blog post with this EXACT structure (use HTML tags):

<h2>[Section 1 heading]</h2>
<p>...</p>
<h2>[Section 2 heading]</h2>
<p>...</p>
... (6~8 sections total)
<h2>FAQ</h2>
<h3>[Question 1]</h3>
<p>[Answer]</p>
<h3>[Question 2]</h3>
<p>[Answer]</p>
... (4~5 FAQ items)

Requirements:
- Title: "${title}"
- Category: ${category}, Area: ${area}
- Keywords to include naturally: ${keywords.join(', ')}
- Length: 1000~1500 words
- Tone: helpful travel guide, friendly, informative
- Always mention: English booking, WhatsApp, foreigner-friendly
- Include practical tips: what to expect, how to book, price ranges in KRW
- NO markdown, use HTML only
- NO intro like "In this article..." — dive straight into valuable content

Also provide (after the HTML content, separated by ---JSON---):
{"metaDescription":"[155 chars max]","excerpt":"[2 sentences summary]","tags":["tag1","tag2","tag3","tag4","tag5"]}`

  try {
    const res = await fetch('https://api.genspark.ai/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
      body: JSON.stringify({
        model: 'claude-haiku-4-5',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 3000
      })
    })
    if (!res.ok) return null
    const data: any = await res.json()
    const raw = data.choices?.[0]?.message?.content || ''
    if (!raw) return null

    const parts = raw.split('---JSON---')
    const htmlContent = parts[0].trim()
    let meta = { metaDescription: '', excerpt: '', tags: [] as string[] }
    if (parts[1]) {
      try {
        const jsonStr = parts[1].trim().replace(/```json|```/g, '').trim()
        meta = JSON.parse(jsonStr)
      } catch(e) {}
    }
    return {
      content: htmlContent,
      excerpt: meta.excerpt || htmlContent.replace(/<[^>]+>/g, '').slice(0, 200),
      metaDescription: meta.metaDescription || '',
      tags: Array.isArray(meta.tags) ? meta.tags : []
    }
  } catch(e) { return null }
}

