// ── GA4 Data API 프록시 ──
// GA4 서비스 계정 JWT 생성 (RS256)
async function makeGa4Jwt(serviceAccountJson: string, scope = 'https://www.googleapis.com/auth/analytics.readonly'): Promise<string> {
  const sa = JSON.parse(serviceAccountJson)
  const now = Math.floor(Date.now() / 1000)
  const header = { alg: 'RS256', typ: 'JWT' }
  const payload = {
    iss: sa.client_email,
    scope,
    aud: 'https://oauth2.googleapis.com/token',
    iat: now,
    exp: now + 3600
  }
  const b64 = (obj: object) => btoa(JSON.stringify(obj)).replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_')
  const unsigned = `${b64(header)}.${b64(payload)}`

  // PEM → CryptoKey
  const pem = sa.private_key.replace(/-----[^-]+-----/g,'').replace(/\s/g,'')
  const der = Uint8Array.from(atob(pem), c => c.charCodeAt(0))
  const key = await crypto.subtle.importKey(
    'pkcs8', der.buffer,
    { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
    false, ['sign']
  )
  const sig = await crypto.subtle.sign('RSASSA-PKCS1-v1_5', key, new TextEncoder().encode(unsigned))
  const sigB64 = btoa(String.fromCharCode(...new Uint8Array(sig))).replace(/=/g,'').replace(/\+/g,'-').replace(/\//g,'_')
  return `${unsigned}.${sigB64}`
}

async function getGa4Token(serviceAccountJson: string, scope?: string): Promise<string> {
  const jwt = await makeGa4Jwt(serviceAccountJson, scope)
  const r = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=urn%3Aietf%3Aparams%3Aoauth%3Agrant-type%3Ajwt-bearer&assertion=${jwt}`
  })
  const d: any = await r.json()
  return d.access_token
}

app.get('/api/analytics', async (c) => {
  try {
    // Cloudflare Workers: c.env 우선 → process.env → 내장 기본값
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY
      || (typeof process !== 'undefined' ? process.env.GA4_SERVICE_ACCOUNT_KEY : undefined)
      || GA4_SA_KEY_DEFAULT
    const propId = (c.env as any)?.GA4_PROPERTY_ID
      || (typeof process !== 'undefined' ? process.env.GA4_PROPERTY_ID : undefined)
      || GA4_PROPERTY_ID_DEFAULT

    if (!saKey || !propId) {
      return c.json({ error: 'GA4_NOT_CONFIGURED' }, 503)
    }

    const days = parseInt(c.req.query('days') || '7')
    const startDate = `${days}daysAgo`
    const token = await getGa4Token(saKey)

    const ga4Fetch = (body: object) => fetch(
      `https://analyticsdata.googleapis.com/v1beta/properties/${propId}:runReport`,
      { method: 'POST', headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
    ).then(r => r.json())

    // 병렬로 모든 데이터 요청
    const [overview, daily, countries, pages, sources, devices] = await Promise.all([
      // 1. 핵심 지표 (전체 기간)
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        metrics: [
          { name: 'totalUsers' }, { name: 'screenPageViews' },
          { name: 'newUsers' }, { name: 'averageSessionDuration' }
        ]
      }),
      // 2. 일별 방문자
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'date' }],
        metrics: [{ name: 'totalUsers' }, { name: 'screenPageViews' }],
        orderBys: [{ dimension: { dimensionName: 'date' } }]
      }),
      // 3. 국가별
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'country' }],
        metrics: [{ name: 'totalUsers' }],
        orderBys: [{ metric: { metricName: 'totalUsers' }, desc: true }],
        limit: 8
      }),
      // 4. 인기 페이지
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'pagePath' }, { name: 'pageTitle' }],
        metrics: [{ name: 'screenPageViews' }, { name: 'totalUsers' }],
        orderBys: [{ metric: { metricName: 'screenPageViews' }, desc: true }],
        limit: 10
      }),
      // 5. 유입 경로
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'sessionDefaultChannelGroup' }],
        metrics: [{ name: 'sessions' }],
        orderBys: [{ metric: { metricName: 'sessions' }, desc: true }],
        limit: 6
      }),
      // 6. 디바이스
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'deviceCategory' }],
        metrics: [{ name: 'totalUsers' }]
      })
    ])

    // ── GA4 소스/매체 상세 (session source / medium)
    const [sourceMedium, landingPages] = await Promise.all([
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'sessionSourceMedium' }],
        metrics: [{ name: 'sessions' }, { name: 'totalUsers' }],
        orderBys: [{ metric: { metricName: 'sessions' }, desc: true }],
        limit: 10
      }),
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'landingPage' }],
        metrics: [{ name: 'sessions' }, { name: 'bounceRate' }],
        orderBys: [{ metric: { metricName: 'sessions' }, desc: true }],
        limit: 10
      })
    ])

    // ── 행동 이벤트: 영상 스와이프 / 검색 / WhatsApp 클릭 ──
    const [videoSwipe, videoSummary, searchEvent, searchClick, whatsappClick] = await Promise.all([
      // 영상 넘김 (video_swipe) — 평균 몇 번 넘기나
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        metrics: [{ name: 'eventCount' }, { name: 'totalUsers' }],
        dimensionFilter: { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'video_swipe' } } }
      }),
      // 세션당 영상 요약 (session_video_summary)
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'customEvent:total_videos_seen' }],
        metrics: [{ name: 'eventCount' }],
        dimensionFilter: { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'session_video_summary' } } },
        orderBys: [{ metric: { metricName: 'eventCount' }, desc: true }],
        limit: 10
      }),
      // 검색어 top 10
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'customEvent:search_term' }],
        metrics: [{ name: 'eventCount' }],
        dimensionFilter: { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'search' } } },
        orderBys: [{ metric: { metricName: 'eventCount' }, desc: true }],
        limit: 10
      }),
      // 검색 후 클릭된 업체 top 10
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'customEvent:shop_name' }],
        metrics: [{ name: 'eventCount' }],
        dimensionFilter: { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'search_shop_click' } } },
        orderBys: [{ metric: { metricName: 'eventCount' }, desc: true }],
        limit: 10
      }),
      // WhatsApp 클릭 업체 top 10
      ga4Fetch({
        dateRanges: [{ startDate, endDate: 'today' }],
        dimensions: [{ name: 'customEvent:shop_name' }, { name: 'customEvent:shop_category' }],
        metrics: [{ name: 'eventCount' }],
        dimensionFilter: { filter: { fieldName: 'eventName', stringFilter: { matchType: 'EXACT', value: 'whatsapp_click' } } },
        orderBys: [{ metric: { metricName: 'eventCount' }, desc: true }],
        limit: 10
      })
    ])

    return c.json({ overview, daily, countries, pages, sources, devices, sourceMedium, landingPages, videoSwipe, videoSummary, searchEvent, searchClick, whatsappClick })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── 서치콘솔 API (검색어 + 페이지별 노출/클릭)
app.get('/api/search-console', async (c) => {
  try {
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY
      || (typeof process !== 'undefined' ? process.env.GA4_SERVICE_ACCOUNT_KEY : undefined)
      || GA4_SA_KEY_DEFAULT

    const days = parseInt(c.req.query('days') || '28')
    const endDate = new Date().toISOString().slice(0, 10)
    const startDate = new Date(Date.now() - days * 86400000).toISOString().slice(0, 10)
    const siteUrl = 'https://seoulbeautytrip.com'

    const token = await getGa4Token(saKey, 'https://www.googleapis.com/auth/webmasters.readonly')

    const scFetch = (body: object) => fetch(
      `https://searchconsole.googleapis.com/webmasters/v3/sites/${encodeURIComponent(siteUrl)}/searchAnalytics/query`,
      { method: 'POST', headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
    ).then(r => r.json())

    const [keywords, pages, countries, devices] = await Promise.all([
      scFetch({ startDate, endDate, dimensions: ['query'], rowLimit: 20, dataState: 'all' }),
      scFetch({ startDate, endDate, dimensions: ['page'], rowLimit: 15, dataState: 'all' }),
      scFetch({ startDate, endDate, dimensions: ['country'], rowLimit: 10, dataState: 'all' }),
      scFetch({ startDate, endDate, dimensions: ['device'], rowLimit: 5, dataState: 'all' })
    ])

    return c.json({ keywords, pages, countries, devices, startDate, endDate })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── 페이지별 키워드 드릴다운 API ──
app.get('/api/search-console/page-keywords', async (c) => {
  try {
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY
      || (typeof process !== 'undefined' ? process.env.GA4_SERVICE_ACCOUNT_KEY : undefined)
      || GA4_SA_KEY_DEFAULT

    const pageUrl = c.req.query('page') // e.g. https://seoulbeautytrip.com/best/clinic/gangnam
    if (!pageUrl) return c.json({ error: 'page param required' }, 400)

    const days = parseInt(c.req.query('days') || '28')
    const endDate = new Date().toISOString().slice(0, 10)
    const startDate = new Date(Date.now() - days * 86400000).toISOString().slice(0, 10)
    const siteUrl = 'https://seoulbeautytrip.com'

    const token = await getGa4Token(saKey, 'https://www.googleapis.com/auth/webmasters.readonly')

    const gscQuery = (body: object) => fetch(
      `https://searchconsole.googleapis.com/webmasters/v3/sites/${encodeURIComponent(siteUrl)}/searchAnalytics/query`,
      { method: 'POST', headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' }, body: JSON.stringify(body) }
    ).then(r => r.json())

    // ① 먼저 query+page 전체 1000행으로 해당 페이지 필터링 시도
    //    → GSC 프라이버시 임계값 우회 (노출 적은 페이지도 query+page 집계에는 포함됨)
    const resQP = await gscQuery({ startDate, endDate, dimensions: ['query', 'page'], rowLimit: 1000, dataState: 'all' })
    const allRows: any[] = resQP.rows || []
    const filtered = allRows.filter((r: any) => r.keys[1] === pageUrl)

    let rows: any[]

    if (filtered.length > 0) {
      // query+page에서 해당 페이지 키워드 발견 → 집계
      const queryMap = new Map<string, { clicks: number; impressions: number; position: number; count: number }>()
      for (const r of filtered) {
        const q = r.keys[0]
        const ex = queryMap.get(q)
        if (ex) { ex.clicks += r.clicks; ex.impressions += r.impressions; ex.position += r.position; ex.count++ }
        else { queryMap.set(q, { clicks: r.clicks, impressions: r.impressions, position: r.position, count: 1 }) }
      }
      rows = Array.from(queryMap.entries())
        .map(([q, v]) => ({ keys: [q], clicks: v.clicks, impressions: v.impressions, ctr: v.impressions > 0 ? v.clicks / v.impressions : 0, position: v.position / v.count }))
        .sort((a, b) => b.impressions - a.impressions).slice(0, 25)
    } else {
      // ② fallback: dimensionFilterGroups 방식 (노출 충분한 페이지용)
      const resFB = await gscQuery({
        startDate, endDate,
        dimensions: ['query'],
        dimensionFilterGroups: [{ filters: [{ dimension: 'page', operator: 'equals', expression: pageUrl }] }],
        rowLimit: 25, dataState: 'all'
      })
      rows = resFB.rows || []
    }

    return c.json({ page: pageUrl, keywords: { rows, responseAggregationType: 'byPage' }, startDate, endDate })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── GSC URL Inspection API — URL 색인 상태 직접 확인 ──
// URL Inspection API는 webmasters (full scope) 필요 - readonly로는 403 발생
app.get('/api/search-console/inspect', async (c) => {
  try {
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY
      || (typeof process !== 'undefined' ? process.env.GA4_SERVICE_ACCOUNT_KEY : undefined)
      || GA4_SA_KEY_DEFAULT

    const inspectUrl = c.req.query('url')
    if (!inspectUrl) return c.json({ error: 'url param required (full URL)' }, 400)

    // URL Inspection API는 webmasters full scope 필요 (readonly X)
    const token = await getGa4Token(saKey, 'https://www.googleapis.com/auth/webmasters')

    // GSC 속성 형식 두 가지 모두 시도
    // sc-domain: → 도메인 속성 (DNS 인증), https:// → URL 접두어 속성
    const siteUrlCandidates = [
      'sc-domain:seoulbeautytrip.com',
      'https://seoulbeautytrip.com/'
    ]

    let data: any = null
    let usedSiteUrl = ''

    for (const siteUrl of siteUrlCandidates) {
      const res = await fetch(
        'https://searchconsole.googleapis.com/v1/urlInspection/index:inspect',
        {
          method: 'POST',
          headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
          body: JSON.stringify({ inspectionUrl: inspectUrl, siteUrl })
        }
      )
      const d: any = await res.json()
      // 403이면 다음 siteUrl 형식 시도
      if (d?.error?.code === 403 || d?.error?.status === 'PERMISSION_DENIED') {
        data = d
        continue
      }
      data = d
      usedSiteUrl = siteUrl
      break
    }

    // 핵심 필드만 추출해서 읽기 쉽게 반환
    const ir = data?.inspectionResult
    const ii = ir?.indexStatusResult
    const ri = ir?.richResultsResult
    const mobile = ir?.mobileUsabilityResult

    return c.json({
      url: inspectUrl,
      siteUrlUsed: usedSiteUrl || '(all failed - check GSC owner permission)',
      verdict: ii?.verdict,                          // PASS / FAIL / NEUTRAL / EXCLUDED
      coverageState: ii?.coverageState,              // Submitted and indexed / Discovered... 등
      robotsTxtState: ii?.robotsTxtState,            // ALLOWED / DISALLOWED
      indexingState: ii?.indexingState,              // INDEXING_ALLOWED / BLOCKED_BY_META_TAG 등
      lastCrawlTime: ii?.lastCrawlTime,
      pageFetchState: ii?.pageFetchState,            // SUCCESSFUL / SOFT_404 등
      googleCanonical: ii?.googleCanonical,          // ★ 구글이 선택한 canonical URL
      userCanonical: ii?.userDeclaredCanonical,      // 우리가 선언한 canonical URL
      sitemap: ii?.sitemap,
      referringUrls: ii?.referringUrls,
      crawledAs: ii?.crawledAs,
      mobileVerdict: mobile?.verdict,
      richResultsVerdict: ri?.verdict,
      raw: data                                      // 전체 raw 데이터도 포함
    })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ── GSC 커버리지 이슈 목록 조회 (인덱싱 문제 URL 배치 확인) ──
app.get('/api/search-console/coverage', async (c) => {
  try {
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY
      || (typeof process !== 'undefined' ? process.env.GA4_SERVICE_ACCOUNT_KEY : undefined)
      || GA4_SA_KEY_DEFAULT

    const urls = c.req.query('urls')  // 쉼표로 구분된 URL 목록
    if (!urls) return c.json({ error: 'urls param required (comma-separated full URLs)' }, 400)

    const urlList = urls.split(',').map(u => u.trim()).filter(Boolean).slice(0, 10) // 최대 10개

    // URL Inspection API는 webmasters full scope 필요
    const token = await getGa4Token(saKey, 'https://www.googleapis.com/auth/webmasters')

    // sc-domain 형식 우선 시도, 실패시 https:// 형식
    const siteUrlCandidates = [
      'sc-domain:seoulbeautytrip.com',
      'https://seoulbeautytrip.com/'
    ]

    // 작동하는 siteUrl 형식 먼저 확인 (첫 번째 URL로 probe)
    let activeSiteUrl = siteUrlCandidates[0]
    if (urlList.length > 0) {
      for (const siteUrl of siteUrlCandidates) {
        const probeRes = await fetch(
          'https://searchconsole.googleapis.com/v1/urlInspection/index:inspect',
          {
            method: 'POST',
            headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ inspectionUrl: urlList[0], siteUrl })
          }
        )
        const probeData: any = await probeRes.json()
        if (!probeData?.error || probeData?.error?.code !== 403) {
          activeSiteUrl = siteUrl
          break
        }
      }
    }

    const results = await Promise.all(urlList.map(async (inspectUrl) => {
      try {
        const res = await fetch(
          'https://searchconsole.googleapis.com/v1/urlInspection/index:inspect',
          {
            method: 'POST',
            headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
            body: JSON.stringify({ inspectionUrl: inspectUrl, siteUrl: activeSiteUrl })
          }
        )
        const data: any = await res.json()
        if (data?.error) return { url: inspectUrl, error: `${data.error.code}: ${data.error.message}`, siteUrlUsed: activeSiteUrl }
        const ii = data?.inspectionResult?.indexStatusResult
        return {
          url: inspectUrl,
          siteUrlUsed: activeSiteUrl,
          verdict: ii?.verdict,
          coverageState: ii?.coverageState,
          googleCanonical: ii?.googleCanonical,
          userCanonical: ii?.userDeclaredCanonical,
          lastCrawlTime: ii?.lastCrawlTime,
          indexingState: ii?.indexingState,
          pageFetchState: ii?.pageFetchState
        }
      } catch (e: any) {
        return { url: inspectUrl, error: e.message }
      }
    }))

    return c.json({ results, siteUrlUsed: activeSiteUrl, checkedAt: new Date().toISOString() })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// ════════════════════════════════════════════
// ── GSC 실검색어 기반 롱테일 블로그 자동 생성 ──
// ════════════════════════════════════════════

// GSC에서 상위 검색어를 가져오는 헬퍼
// - impressions 상위 N개 반환
// - type: 'gap' = 클릭 없이 노출만 많은 것(CTR 개선 기회) | 'top' = 전체 상위
async function getGscTopQueries(saKey: string, opts: {
  days?: number, rowLimit?: number, type?: 'gap' | 'top', minImpressions?: number
} = {}): Promise<Array<{ query: string, clicks: number, impressions: number, ctr: number, position: number }>> {
  const { days = 28, rowLimit = 100, type = 'gap', minImpressions = 5 } = opts
  const endDate = new Date().toISOString().slice(0, 10)
  const startDate = new Date(Date.now() - days * 86400000).toISOString().slice(0, 10)
  const siteUrl = 'https://seoulbeautytrip.com'

  const token = await getGa4Token(saKey, 'https://www.googleapis.com/auth/webmasters.readonly')
  const res: any = await fetch(
    `https://searchconsole.googleapis.com/webmasters/v3/sites/${encodeURIComponent(siteUrl)}/searchAnalytics/query`,
    {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ startDate, endDate, dimensions: ['query'], rowLimit, dataState: 'all' })
    }
  ).then(r => r.json())

  const rows: any[] = res.rows || []
  const filtered = rows
    .filter((r: any) => r.impressions >= minImpressions)
    .map((r: any) => ({
      query: r.keys[0] as string,
      clicks: r.clicks as number,
      impressions: r.impressions as number,
      ctr: r.ctr as number,
      position: r.position as number
    }))

  if (type === 'gap') {
    // CTR gap: 노출 많은데 클릭 적음 → 새 블로그 글이 가장 필요한 키워드
    return filtered
      .filter(r => r.clicks < 3)           // 클릭 거의 없음
      .sort((a, b) => b.impressions - a.impressions) // 노출 많은 순
  }
  // top: 전체 상위 (노출 순)
  return filtered.sort((a, b) => b.impressions - a.impressions)
}

// GSC 검색어 1개 → haiku로 롱테일 블로그 생성
async function autoGenGscBlog(query: string, context: {
  category?: string, area?: string, relatedQueries?: string[]
}, apiKey: string, sql: any): Promise<{ id: string, slug: string, title: string } | null> {
  if (!apiKey || !query) return null

  // 이미 같은 타이틀/슬러그 블로그 있으면 스킵
  const slug = makeBlogSlug(query + ' seoul guide')
  const dupCheck = await sql`SELECT id FROM blog_posts WHERE slug=${slug} LIMIT 1`.catch(() => [])
  if (dupCheck.length > 0) return null

  // 카테고리 추론 (검색어에서)
  const catHints: Record<string, string> = {
    clinic: 'skin clinic', skincare: 'skincare', hair: 'hair salon',
    headspa: 'head spa', tattoo: 'eyebrow tattoo', dental: 'dental', makeup: 'personal color'
  }
  const queryCat = context.category
    || Object.entries(catHints).find(([k]) => query.toLowerCase().includes(k))?.[1]
    || 'K-beauty'
  const area = context.area || 'Seoul'
  const relatedStr = (context.relatedQueries || []).slice(0, 4).join(', ')

  // 사람이 쓴 것처럼: 검색어가 질문이라면 그 질문에 직접 답하는 구조
  const isQuestion = /\?|is |are |do |does |how |what |where |which |can |should /.test(query.toLowerCase())
  const titleBase = isQuestion
    ? query.replace(/\?$/, '').trim()
    : `${query} — Complete Guide for Foreigners`
  const title = titleBase.charAt(0).toUpperCase() + titleBase.slice(1)

  const prompt = `You are a Seoul K-beauty travel writer for seoulbeautytrip.com.
A real person searched Google for: "${query}"
Write a helpful, honest blog post that DIRECTLY answers what they're looking for.

Context: ${queryCat} in ${area}, Seoul. Related searches: ${relatedStr || 'Seoul beauty, K-beauty foreigners'}

Write HTML with this structure:
<h2>[Direct answer headline]</h2>
<p>[Lead paragraph — answer the query in 2-3 sentences]</p>
<h2>What You Need to Know</h2>
<p>...</p>
<h2>Our Honest Take</h2>
<p>[Include specific details: what's good, what to watch out for, price range hints without fake numbers]</p>
<h2>How to Book as a Foreigner (Step by Step)</h2>
<p>...</p>
<h2>Tips Before You Go</h2>
<ul><li>...</li></ul>
<h2>FAQ</h2>
<h3>[Related question 1]</h3><p>...</p>
<h3>[Related question 2]</h3><p>...</p>
<h3>[Related question 3]</h3><p>...</p>

Rules:
- 700-900 words, HTML only (no markdown)
- Write like a real person who has been there — not a brochure
- Mention WhatsApp booking via Seoul Beauty Trip as the easy English option
- Naturally include: "${query}" and related terms like: ${relatedStr}
- No fake prices or fake clinic names
- End with a soft CTA: "Browse vetted options on Seoul Beauty Trip →"

After HTML add ---JSON---
{"metaDescription":"[max 155 chars, include '${query}' naturally]","excerpt":"[2 sentence hook]","tags":["${query}","${queryCat} Seoul","Seoul beauty foreigners","K-beauty guide 2026","${area} ${queryCat}"],"category":"${context.category || 'guide'}"}`

  try {
    const res = await fetch('https://www.genspark.ai/api/llm_proxy/v1/chat/completions', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${apiKey}` },
      body: JSON.stringify({
        model: 'claude-haiku-4-5',
        messages: [{ role: 'user', content: prompt }],
        max_tokens: 2800,
        temperature: 0.65
      })
    })
    if (!res.ok) return null
    const data: any = await res.json()
    const raw: string = data.choices?.[0]?.message?.content || ''
    if (!raw || raw.length < 200) return null

    const parts = raw.split('---JSON---')
    const htmlContent = parts[0].trim()
    if (htmlContent.length < 300) return null

    let metaDescription = `${query} — complete guide for foreigners visiting Seoul K-beauty spots. Book via WhatsApp with English support.`
    let excerpt = `Everything you need to know about ${query} as a foreigner in Seoul.`
    let tags: string[] = [query, `${queryCat} Seoul`, 'Seoul beauty guide']
    let finalCat = context.category || 'guide'

    if (parts[1]) {
      try {
        const m = JSON.parse(parts[1].trim().replace(/```json|```/g, '').trim())
        if (m.metaDescription) metaDescription = m.metaDescription
        if (m.excerpt) excerpt = m.excerpt
        if (Array.isArray(m.tags)) tags = m.tags
        if (m.category) finalCat = m.category
      } catch {}
    }

    const blogId = 'b' + Date.now() + Math.random().toString(36).slice(2, 5)
    const now = new Date().toISOString().slice(0, 10)

    await sql`INSERT INTO blog_posts
      (id, slug, title, content, excerpt, meta_description, category, area, tags, status, views, shop_id, created_at, updated_at)
      VALUES (
        ${blogId}, ${slug}, ${title}, ${htmlContent}, ${excerpt}, ${metaDescription},
        ${finalCat}, ${area}, ${JSON.stringify(tags)}, 'published', 0, null, ${now}, ${now}
      )`

    return { id: blogId, slug, title }
  } catch {
    return null
  }
}

// POST /api/admin/gen-gsc-blogs
// GSC 실검색어 → 롱테일 블로그 자동 생성 (어드민 트리거)
// body: { days?:28, limit?:10, type?:'gap'|'top', dryRun?:false }
app.post('/api/admin/gen-gsc-blogs', async (c) => {
  try {
    const sql = getDb(c.env)
    const apiKey = c.env?.GSK_TOKEN || (c.env as any)?.gsk_token || ''
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY || GA4_SA_KEY_DEFAULT
    if (!apiKey) return c.json({ error: 'GSK_TOKEN not configured' }, 500)

    const body: any = await c.req.json().catch(() => ({}))
    const days       = Number(body.days   ?? 28)
    const limit      = Number(body.limit  ?? 10)
    const type       = (body.type === 'top' ? 'top' : 'gap') as 'gap' | 'top'
    const dryRun     = body.dryRun === true
    const minImpressions = Number(body.minImpressions ?? 5)

    // ① GSC에서 검색어 가져오기
    const queries = await getGscTopQueries(saKey, { days, rowLimit: 200, type, minImpressions })

    if (queries.length === 0) {
      return c.json({ message: 'No qualifying queries found from GSC', queries: [] })
    }

    // ② 이미 블로그 있는 slug 제외 (DB 조회)
    const existingSlugs = await sql`SELECT slug FROM blog_posts WHERE status='published'`.catch(() => [])
    const existingSet = new Set((existingSlugs as any[]).map((r: any) => r.slug))

    const candidates = queries
      .filter(q => !existingSet.has(makeBlogSlug(q.query + ' seoul guide')))
      .slice(0, limit)

    if (dryRun) {
      return c.json({
        dryRun: true,
        total: queries.length,
        candidates: candidates.map(q => ({
          query: q.query,
          impressions: q.impressions,
          clicks: q.clicks,
          position: Math.round(q.position * 10) / 10,
          targetSlug: makeBlogSlug(q.query + ' seoul guide')
        }))
      })
    }

    // ③ 각 검색어로 블로그 생성 (순차 실행, rate limit 방지)
    const results: Array<{ query: string, status: string, slug?: string, title?: string }> = []

    for (const q of candidates) {
      try {
        // 검색어에서 카테고리/지역 추론
        const catMap: Record<string, string> = {
          'clinic': 'clinic', 'skin': 'clinic', 'derma': 'clinic', 'botox': 'clinic', 'filler': 'clinic',
          'hair': 'hair', 'salon': 'hair', 'perm': 'hair',
          'head spa': 'headspa', 'scalp': 'headspa',
          'tattoo': 'tattoo', 'eyebrow': 'tattoo', 'microblading': 'tattoo',
          'dental': 'dental', 'teeth': 'dental',
          'makeup': 'makeup', 'color analysis': 'makeup', 'personal color': 'makeup'
        }
        const qLow = q.query.toLowerCase()
        const cat = Object.entries(catMap).find(([k]) => qLow.includes(k))?.[1] || 'guide'

        // 지역 추론
        const areas = ['gangnam', 'hongdae', 'sinchon', 'myeongdong', 'itaewon', 'insadong', 'apgujeong', 'cheongdam', 'mapo', 'jongno', 'dongdaemun']
        const detectedArea = areas.find(a => qLow.includes(a))
        const area = detectedArea ? detectedArea.charAt(0).toUpperCase() + detectedArea.slice(1) : 'Seoul'

        // 관련 검색어 (같은 카테고리의 다른 queries에서)
        const relatedQueries = candidates
          .filter(rq => rq.query !== q.query)
          .slice(0, 4)
          .map(rq => rq.query)

        const result = await autoGenGscBlog(q.query, { category: cat, area, relatedQueries }, apiKey, sql)
        if (result) {
          results.push({ query: q.query, status: 'created', slug: result.slug, title: result.title })
        } else {
          results.push({ query: q.query, status: 'skipped (duplicate or error)' })
        }
      } catch (e: any) {
        results.push({ query: q.query, status: `error: ${e.message}` })
      }
      // rate limit 방지: haiku도 TPM 제한 있음
      await new Promise(r => setTimeout(r, 1200))
    }

    const created = results.filter(r => r.status === 'created').length
    return c.json({ total: candidates.length, created, results })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// GET /api/admin/gsc-query-preview
// dryRun 없이 GSC 키워드 미리보기만 (블로그 생성 없음)
// GET /api/admin/debug-blog-photos?slug=xxx — 블로그 포토 갤러리 디버그
app.get('/api/admin/debug-blog-photos', async (c) => {
  try {
    await ensureDb(c.env)
    const sql = getDb(c.env)
    const slug = c.req.query('slug') || ''
    if (!slug) return c.json({ error: 'slug required' }, 400)

    const rows = await sql`SELECT id, slug, shop_id FROM blog_posts WHERE slug=${slug} LIMIT 1`
    if (!rows.length) return c.json({ error: 'blog not found' }, 404)
    const post = rows[0]

    if (!post.shop_id) return c.json({ shop_id: null, photos: [] })

    const shopRow = await sql`SELECT id, thumbnail, photos FROM shops WHERE id=${post.shop_id} LIMIT 1`
    if (!shopRow.length) return c.json({ shop_id: post.shop_id, shop_found: false })

    const rawPhotos = shopRow[0].photos
    const rawType = Array.isArray(rawPhotos) ? 'array' : typeof rawPhotos
    const photoArr: string[] = Array.isArray(rawPhotos)
      ? rawPhotos
      : (typeof rawPhotos === 'string' ? JSON.parse(rawPhotos || '[]') : [])

    const thumb = shopRow[0].thumbnail || ''
    // photos[0] == thumbnail인 경우가 많으므로 slice(1,7) 사용
    const galleryUrls = photoArr
      .map((u: any) => String(u || '').trim())
      .filter((u: string) => u.startsWith('http'))
      .slice(1, 7)

    return c.json({
      blog_slug: post.slug,
      shop_id: post.shop_id,
      thumbnail: thumb.slice(0, 80),
      rawPhotosType: rawType,
      photoArrLen: photoArr.length,
      galleryCount: galleryUrls.length,
      urls: galleryUrls.map((u: string) => u.slice(0, 80))
    })
  } catch (e: any) {
    return c.json({ error: e.message, stack: e.stack?.slice(0, 300) }, 500)
  }
})

app.get('/api/admin/gsc-query-preview', async (c) => {
  try {
    const saKey = (c.env as any)?.GA4_SERVICE_ACCOUNT_KEY || GA4_SA_KEY_DEFAULT
    const days  = Number(c.req.query('days') ?? 28)
    const type  = (c.req.query('type') === 'top' ? 'top' : 'gap') as 'gap' | 'top'
    const minImp = Number(c.req.query('minImpressions') ?? 5)

    const queries = await getGscTopQueries(saKey, { days, rowLimit: 200, type, minImpressions: minImp })
    return c.json({ total: queries.length, queries: queries.slice(0, 50) })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

// POST /api/admin/regen-shop-blog
// 특정 업체의 블로그 글을 재생성 (사진 삽입 + 사람다운 글 + 다크테마)
// body: { shopId: string } 또는 { blogId: string }
app.post('/api/admin/regen-shop-blog', async (c) => {
  try {
    await ensureDb(c.env)
    const sql = getDb(c.env)
    const apiKey = c.env?.GSK_TOKEN || (c.env as any)?.gsk_token || ''
    if (!apiKey) return c.json({ error: 'GSK_TOKEN not configured' }, 500)

    const body: any = await c.req.json().catch(() => ({}))
    const blogId = body.blogId as string | undefined
    const shopId = body.shopId as string | undefined

    // 블로그 글 찾기
    let blogRow: any = null
    if (blogId) {
      const rows = await sql`SELECT * FROM blog_posts WHERE id=${blogId} LIMIT 1`
      blogRow = rows[0]
    } else if (shopId) {
      const rows = await sql`SELECT * FROM blog_posts WHERE shop_id=${shopId} LIMIT 1`
      blogRow = rows[0]
    }
    if (!blogRow) return c.json({ error: 'Blog post not found' }, 404)

    // 업체 정보 조회
    const sid = blogRow.shop_id || shopId
    if (!sid) return c.json({ error: 'No shop_id linked to this blog post' }, 400)

    const shopRows = await sql`SELECT * FROM shops WHERE id=${sid} LIMIT 1`
    if (!shopRows.length) return c.json({ error: 'Shop not found' }, 404)
    const shop = shopRows[0]

    const reviews = Array.isArray(shop.reviews) ? shop.reviews : JSON.parse(shop.reviews || '[]')
    const whyChoose = Array.isArray(shop.why_choose) ? shop.why_choose : JSON.parse(shop.why_choose || '[]')
    const photos: string[] = Array.isArray(shop.photos) ? shop.photos : JSON.parse(shop.photos || '[]')

    // 기존 블로그 삭제 후 재생성 (autoGenShopBlog의 중복 체크를 bypass)
    await sql`DELETE FROM blog_posts WHERE id=${blogRow.id}`

    // autoGenShopBlog 재호출
    await autoGenShopBlog({
      id: sid,
      name: shop.name,
      category: shop.category,
      location: shop.location,
      rating: shop.rating,
      reviewCount: shop.review_count,
      description: shop.description,
      reviews,
      seoText: shop.seo_text || '',
      whyChoose
    }, apiKey, sql)

    // 새로 생성된 블로그 slug 반환
    const newBlog = await sql`SELECT id, slug, title FROM blog_posts WHERE shop_id=${sid} ORDER BY created_at DESC LIMIT 1`.catch(() => [])

    return c.json({
      success: true,
      deleted: blogRow.slug,
      created: newBlog[0] || null
    })
  } catch (e: any) {
    return c.json({ error: e.message }, 500)
  }
})

