// ── 대시보드 유입채널 로드 ──
window.loadDashboardSources = async function() {
  var el = document.getElementById('dash-sources');
  if(!el) return;
  el.innerHTML = '<span style="color:rgba(255,255,255,.25)">로딩 중...</span>';
  try {
    var res = await fetch('/api/analytics?days=7');
    var data = await res.json();
    if(!data.sources || !data.sources.rows) { el.innerHTML = '<span style="color:rgba(255,255,255,.25)">데이터 없음</span>'; return; }
    var total = data.sources.rows.reduce(function(s,r){ return s+parseInt(r.metricValues[0].value||0); },0);
    var colors = {'Direct':'#60a5fa','Organic Search':'#34d399','Organic Social':'#f472b6','Paid Social':'#fbbf24','Unassigned':'rgba(255,255,255,.3)'};
    var icons = {'Direct':'🔗','Organic Search':'🔍','Organic Social':'📱','Paid Social':'💰','Unassigned':'❓'};
    el.innerHTML = data.sources.rows.slice(0,5).map(function(r){
      var ch = r.dimensionValues[0].value;
      var cnt = parseInt(r.metricValues[0].value||0);
      var pct = total>0 ? Math.round(cnt/total*100) : 0;
      var color = colors[ch] || '#a78bfa';
      var icon = icons[ch] || '🌐';
      return '<div style="display:flex;align-items:center;gap:6px">'
        +'<span style="font-size:13px;min-width:18px">'+icon+'</span>'
        +'<span style="flex:1;color:rgba(255,255,255,.75);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">'+ch+'</span>'
        +'<div style="width:50px;height:5px;background:rgba(255,255,255,.08);border-radius:3px;flex-shrink:0"><div style="height:100%;width:'+pct+'%;background:'+color+';border-radius:3px"></div></div>'
        +'<span style="color:rgba(255,255,255,.5);min-width:28px;text-align:right;font-weight:700">'+cnt+'</span>'
        +'</div>';
    }).join('');
    if(total>0){
      el.innerHTML += '<div style="margin-top:8px;padding-top:8px;border-top:1px solid rgba(255,255,255,.06);font-size:10px;color:rgba(255,255,255,.3);text-align:right">총 세션 '+total.toLocaleString()+'회 · <a href="#" id="dash-go-analytics" style="color:#34d399;text-decoration:underline">상세 보기 →</a></div>';
    }
  } catch(e) {
    el.innerHTML = '<span style="color:#ef4444;font-size:11px">로드 실패</span>';
  }
};

// ── 영상 조회수 초기화 ──
window.resetVideoViews = async function() {
  if(!confirm('⚠️ 모든 영상 조회수를 0으로 초기화합니다. 이 작업은 되돌릴 수 없습니다. 계속하시겠습니까?')) return;
  var btn1 = document.getElementById('reset-views-btn');
  var btn2 = document.getElementById('reset-views-btn2');
  var res1 = document.getElementById('reset-views-result');
  var res2 = document.getElementById('reset-views-result2');
  [btn1,btn2].forEach(function(b){ if(b){ b.disabled=true; b.innerHTML='<i class="fas fa-spinner fa-spin"></i> 초기화 중...'; } });
  try {
    var r = await fetch('/api/admin/reset-video-views', {method:'POST'});
    var d = await r.json();
    var msg = d.ok ? '✅ '+d.message : '❌ 실패: '+(d.error||'알 수 없는 오류');
    var color = d.ok ? '#34d399' : '#ef4444';
    [res1,res2].forEach(function(el){ if(el){ el.style.color=color; el.textContent=msg; } });
    if(d.ok) {
      // 대시보드 숫자 업데이트
      var stViews = document.getElementById('st-views');
      if(stViews) stViews.textContent = '0';
      setTimeout(function(){ if(typeof loadShops==='function') loadShops(); }, 500);
    }
  } catch(e) {
    [res1,res2].forEach(function(el){ if(el){ el.style.color='#ef4444'; el.textContent='❌ 네트워크 오류'; } });
  } finally {
    [btn1,btn2].forEach(function(b){ if(b){ b.disabled=false; b.innerHTML='<i class="fas fa-redo"></i> 전체 조회수 초기화'; } });
    if(btn2) btn2.innerHTML='<i class="fas fa-redo"></i> 전체 영상 조회수 초기화';
  }
};

window.loadAnalytics = async function loadAnalytics(days) {
  days = days || 7;
  // 버튼 활성화 상태 변경
  [7,28,90].forEach(function(d){
    var btn = document.getElementById('an-btn-'+d);
    if(!btn) return;
    if(d === days){
      btn.style.background = 'linear-gradient(135deg,#FF4D8D,#9B59B6)';
      btn.style.border = 'none'; btn.style.color = '#fff';
    } else {
      btn.style.background = 'rgba(255,255,255,.07)';
      btn.style.border = '1px solid rgba(255,255,255,.12)';
      btn.style.color = 'rgba(255,255,255,.6)';
    }
  });

  // 로딩 표시
  ['an-users','an-pageviews','an-new-users','an-duration'].forEach(function(id){
    var el = document.getElementById(id);
    if(el) el.textContent = '...';
  });

  try {
    var res = await fetch('/api/analytics?days=' + days);
    var data = await res.json();

    if(data.error === 'GA4_NOT_CONFIGURED') {
      var notice = document.getElementById('an-setup-notice');
      if(notice) notice.style.display = 'block';
      return;
    }
    if(data.error) throw new Error(data.error);

    var notice2 = document.getElementById('an-setup-notice');
    if(notice2) notice2.style.display = 'none';

    // ── 핵심 지표 ──
    var ov = data.overview && data.overview.rows && data.overview.rows[0];
    if(ov) {
      var vals = ov.metricValues;
      var users = parseInt(vals[0].value || 0);
      var pvs   = parseInt(vals[1].value || 0);
      var newU  = parseInt(vals[2].value || 0);
      var dur   = parseFloat(vals[3].value || 0);
      var durMin = Math.floor(dur/60) + 'm ' + Math.floor(dur%60) + 's';

      document.getElementById('an-users').textContent = users.toLocaleString();
      document.getElementById('an-users-sub').textContent = '선택 기간 합계';
      document.getElementById('an-pageviews').textContent = pvs.toLocaleString();
      document.getElementById('an-pv-sub').textContent = '평균 ' + (users > 0 ? (pvs/users).toFixed(1) : 0) + ' 페이지/인';
      document.getElementById('an-new-users').textContent = newU.toLocaleString();
      document.getElementById('an-new-sub').textContent = users > 0 ? '전체의 ' + Math.round(newU/users*100) + '%' : '';
      document.getElementById('an-duration').textContent = durMin;
      document.getElementById('an-dur-sub').textContent = '평균 세션 시간';
    }

    // ── 일별 차트 ──
    if(data.daily && data.daily.rows) {
      var labels = data.daily.rows.map(function(r){ 
        var d2 = r.dimensionValues[0].value;
        return d2.slice(4,6)+'/'+d2.slice(6,8);
      });
      var uData = data.daily.rows.map(function(r){ return parseInt(r.metricValues[0].value||0); });
      var pvData = data.daily.rows.map(function(r){ return parseInt(r.metricValues[1].value||0); });

      var ctx = document.getElementById('an-daily-chart');
      if(_anDailyChart) _anDailyChart.destroy();
      _anDailyChart = new Chart(ctx, {
        type: 'bar',
        data: {
          labels: labels,
          datasets: [
            { label: '방문자', data: uData, backgroundColor: 'rgba(255,77,141,.7)', borderRadius: 4, order: 2 },
            { label: '페이지뷰', data: pvData, type: 'line', borderColor: '#60a5fa', backgroundColor: 'rgba(96,165,250,.1)', tension: 0.4, fill: true, pointRadius: 3, order: 1 }
          ]
        },
        options: {
          responsive: true, maintainAspectRatio: true,
          plugins: { legend: { labels: { color: 'rgba(255,255,255,.6)', font: { size: 11 } } } },
          scales: {
            x: { ticks: { color: 'rgba(255,255,255,.4)', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,.05)' } },
            y: { ticks: { color: 'rgba(255,255,255,.4)', font: { size: 10 } }, grid: { color: 'rgba(255,255,255,.05)' } }
          }
        }
      });
    }

    // ── 국가별 ──
    var cntEl = document.getElementById('an-countries');
    if(cntEl && data.countries && data.countries.rows) {
      var maxC = parseInt(data.countries.rows[0].metricValues[0].value||1);
      var flags = {'South Korea':'🇰🇷','United States':'🇺🇸','Japan':'🇯🇵','China':'🇨🇳','United Kingdom':'🇬🇧','Australia':'🇦🇺','Canada':'🇨🇦','Singapore':'🇸🇬','Taiwan':'🇹🇼','Hong Kong':'🇭🇰','France':'🇫🇷','Germany':'🇩🇪','Thailand':'🇹🇭','Vietnam':'🇻🇳','Philippines':'🇵🇭','Indonesia':'🇮🇩','Malaysia':'🇲🇾'};
      cntEl.innerHTML = data.countries.rows.map(function(r){
        var cn = r.dimensionValues[0].value;
        var uv = parseInt(r.metricValues[0].value||0);
        var pct = Math.round(uv/maxC*100);
        var flag = flags[cn] || '🌍';
        return '<div style="display:flex;align-items:center;gap:6px;font-size:12px">'
          + '<span style="min-width:22px">' + flag + '</span>'
          + '<span style="flex:1;color:rgba(255,255,255,.8);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">' + cn + '</span>'
          + '<div style="width:80px;height:6px;background:rgba(255,255,255,.08);border-radius:3px;overflow:hidden"><div style="height:100%;width:'+pct+'%;background:linear-gradient(90deg,#FF4D8D,#9B59B6);border-radius:3px"></div></div>'
          + '<span style="min-width:28px;text-align:right;color:rgba(255,255,255,.5)">' + uv.toLocaleString() + '</span>'
          + '</div>';
      }).join('');
    }

    // ── 유입 경로 도넛 ──
    if(data.sources && data.sources.rows) {
      var srcLabels = data.sources.rows.map(function(r){ return r.dimensionValues[0].value; });
      var srcData = data.sources.rows.map(function(r){ return parseInt(r.metricValues[0].value||0); });
      var ctx2 = document.getElementById('an-source-chart');
      if(_anSourceChart) _anSourceChart.destroy();
      _anSourceChart = new Chart(ctx2, {
        type: 'doughnut',
        data: {
          labels: srcLabels,
          datasets: [{ data: srcData, backgroundColor: ['#FF4D8D','#60a5fa','#34d399','#fbbf24','#a78bfa','#fb923c'], borderWidth: 0 }]
        },
        options: {
          responsive: true, maintainAspectRatio: true,
          plugins: {
            legend: { position: 'bottom', labels: { color: 'rgba(255,255,255,.6)', font: { size: 10 }, padding: 8 } }
          }
        }
      });
    }

    // ── 인기 페이지 ──
    var pgEl = document.getElementById('an-pages');
    if(pgEl && data.pages && data.pages.rows) {
      var maxP = parseInt(data.pages.rows[0].metricValues[0].value||1);
      pgEl.innerHTML = data.pages.rows.map(function(r, i){
        var path = r.dimensionValues[0].value;
        var title = r.dimensionValues[1].value || path;
        var pvs2 = parseInt(r.metricValues[0].value||0);
        var uvs2 = parseInt(r.metricValues[1].value||0);
        var pct2 = Math.round(pvs2/maxP*100);
        var rankColors = ['#fbbf24','#94a3b8','#b45309','#6366f1','#6366f1'];
        return '<div style="padding:8px 4px;border-bottom:1px solid rgba(255,255,255,.05)">'
          + '<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">'
          + '<span style="font-size:11px;font-weight:900;color:'+(rankColors[i]||'rgba(255,255,255,.3)')+';min-width:16px">'+(i+1)+'</span>'
          + '<span style="font-size:12px;color:rgba(255,255,255,.85);flex:1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + (title.length > 40 ? path : title) + '</span>'
          + '<span style="font-size:11px;color:rgba(255,255,255,.4)">' + pvs2.toLocaleString() + ' 뷰</span>'
          + '</div>'
          + '<div style="display:flex;align-items:center;gap:6px">'
          + '<span style="font-size:10px;color:rgba(255,255,255,.3);min-width:16px"></span>'
          + '<div style="flex:1;height:4px;background:rgba(255,255,255,.06);border-radius:2px"><div style="height:100%;width:'+pct2+'%;background:linear-gradient(90deg,rgba(255,77,141,.6),rgba(155,89,182,.6));border-radius:2px"></div></div>'
          + '<span style="font-size:10px;color:rgba(255,255,255,.3)">' + uvs2.toLocaleString() + '명</span>'
          + '</div>'
          + '</div>';
      }).join('');
    }

    // ── 디바이스 ──
    var devEl = document.getElementById('an-devices');
    if(devEl && data.devices && data.devices.rows) {
      var totalDev = data.devices.rows.reduce(function(s,r){ return s + parseInt(r.metricValues[0].value||0); }, 0);
      var devIcons = { mobile:'📱', desktop:'💻', tablet:'📟' };
      var devColors = { mobile:'#FF4D8D', desktop:'#60a5fa', tablet:'#34d399' };
      devEl.innerHTML = data.devices.rows.map(function(r){
        var cat = r.dimensionValues[0].value.toLowerCase();
        var uv = parseInt(r.metricValues[0].value||0);
        var pct = totalDev > 0 ? Math.round(uv/totalDev*100) : 0;
        return '<div style="text-align:center;padding:12px;background:rgba(255,255,255,.04);border-radius:10px;border:1px solid rgba(255,255,255,.07)">'
          + '<div style="font-size:24px;margin-bottom:4px">' + (devIcons[cat]||'🖥') + '</div>'
          + '<div style="font-size:20px;font-weight:900;color:' + (devColors[cat]||'#fff') + '">' + pct + '%</div>'
          + '<div style="font-size:10px;color:rgba(255,255,255,.4);text-transform:capitalize">' + cat + '</div>'
          + '<div style="font-size:11px;color:rgba(255,255,255,.3);margin-top:2px">' + uv.toLocaleString() + '명</div>'
          + '</div>';
      }).join('');
    }

    // ══ 사용자 행동 분석 ══

    // ── 행동 요약 카드 ──
    var swipeEl = document.getElementById('bh-swipe-count');
    var searchEl = document.getElementById('bh-search-count');
    var waEl2 = document.getElementById('bh-wa-count');
    if(swipeEl && data.videoSwipe && data.videoSwipe.rows && data.videoSwipe.rows[0]){
      swipeEl.textContent = parseInt(data.videoSwipe.rows[0].metricValues[0].value||0).toLocaleString();
    } else if(swipeEl){ swipeEl.textContent = '0'; }
    if(searchEl && data.searchEvent && data.searchEvent.rows && data.searchEvent.rows[0]){
      searchEl.textContent = parseInt(data.searchEvent.rows[0].metricValues[0].value||0).toLocaleString();
    } else if(searchEl){ searchEl.textContent = '0'; }
    if(waEl2 && data.whatsappClick && data.whatsappClick.rows && data.whatsappClick.rows[0]){
      var waTot = data.whatsappClick.rows.reduce(function(s,r){return s+parseInt(r.metricValues[0].value||0);},0);
      waEl2.textContent = waTot.toLocaleString();
    } else if(waEl2){ waEl2.textContent = '0'; }

    // ── 세션당 영상 시청 개수 분포 ──
    var vdEl = document.getElementById('bh-video-dist');
    if(vdEl){
      var vdRows = (data.videoSummary && data.videoSummary.rows) || [];
      var NO_BH = '<div style="color:rgba(255,255,255,.25);font-size:11px;padding:10px 0;text-align:center">📊 데이터 수집 중...<br><span style="font-size:10px;opacity:.6">방문자가 쌓이면 표시됩니다</span></div>';
      if(!vdRows.length){ vdEl.innerHTML = NO_BH; }
      else {
        var vdMax = parseInt(vdRows[0].metricValues[0].value||1);
        vdEl.innerHTML = vdRows.map(function(r){
          var cnt = r.dimensionValues[0].value;
          var ev = parseInt(r.metricValues[0].value||0);
          var pct = Math.round(ev/vdMax*100);
          var label = cnt==='1'?'1개만 보고 나감':cnt+'개 보고 나감';
          return '<div style="display:flex;align-items:center;gap:6px">'
            +'<span style="min-width:90px;color:rgba(255,255,255,.75)">'+label+'</span>'
            +'<div style="flex:1;height:6px;background:rgba(255,255,255,.07);border-radius:3px"><div style="height:100%;width:'+pct+'%;background:linear-gradient(90deg,#FF4D8D,#9B59B6);border-radius:3px"></div></div>'
            +'<span style="min-width:22px;text-align:right;color:rgba(255,255,255,.4)">'+ev+'</span>'
            +'</div>';
        }).join('');
      }
    }

    // ── 사이트 내 검색어 Top 10 ──
    var stEl = document.getElementById('bh-search-terms');
    if(stEl){
      var stRows = (data.searchEvent && data.searchEvent.rows) || [];
      if(!stRows.length){ stEl.innerHTML = '<div style="color:rgba(255,255,255,.25);font-size:11px;padding:10px 0;text-align:center">🔍 검색 데이터 수집 중...</div>'; }
      else {
        var stMax = parseInt(stRows[0].metricValues[0].value||1);
        stEl.innerHTML = stRows.map(function(r, i){
          var term = r.dimensionValues[0].value || '(없음)';
          var ev = parseInt(r.metricValues[0].value||0);
          var pct = Math.round(ev/stMax*100);
          var rankC = ['#fbbf24','#94a3b8','#b45309'];
          return '<div style="display:flex;align-items:center;gap:6px">'
            +'<span style="font-size:10px;font-weight:900;color:'+(rankC[i]||'rgba(255,255,255,.25)')+';min-width:14px">'+(i+1)+'</span>'
            +'<span style="flex:1;color:rgba(255,255,255,.8);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+term+'</span>'
            +'<div style="width:50px;height:5px;background:rgba(255,255,255,.07);border-radius:3px"><div style="height:100%;width:'+pct+'%;background:#60a5fa;border-radius:3px"></div></div>'
            +'<span style="min-width:20px;text-align:right;color:rgba(255,255,255,.4)">'+ev+'</span>'
            +'</div>';
        }).join('');
      }
    }

    // ── 검색 후 클릭된 업체 ──
    var scEl2 = document.getElementById('bh-search-clicks');
    if(scEl2){
      var scRows2 = (data.searchClick && data.searchClick.rows) || [];
      if(!scRows2.length){ scEl2.innerHTML = '<div style="color:rgba(255,255,255,.25);font-size:11px;padding:10px 0;text-align:center">🏪 데이터 수집 중...</div>'; }
      else {
        var scMax2 = parseInt(scRows2[0].metricValues[0].value||1);
        scEl2.innerHTML = scRows2.map(function(r, i){
          var shop2 = r.dimensionValues[0].value || '(없음)';
          var ev = parseInt(r.metricValues[0].value||0);
          var pct = Math.round(ev/scMax2*100);
          var rankC2 = ['#fbbf24','#94a3b8','#b45309'];
          return '<div style="display:flex;align-items:center;gap:6px">'
            +'<span style="font-size:10px;font-weight:900;color:'+(rankC2[i]||'rgba(255,255,255,.25)')+';min-width:14px">'+(i+1)+'</span>'
            +'<span style="flex:1;color:rgba(255,255,255,.8);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+shop2+'</span>'
            +'<div style="width:50px;height:5px;background:rgba(255,255,255,.07);border-radius:3px"><div style="height:100%;width:'+pct+'%;background:#fbbf24;border-radius:3px"></div></div>'
            +'<span style="min-width:20px;text-align:right;color:rgba(255,255,255,.4)">'+ev+'</span>'
            +'</div>';
        }).join('');
      }
    }

    // ── WhatsApp 클릭 업체 Top 10 ──
    var waShEl = document.getElementById('bh-wa-shops');
    if(waShEl){
      var waRows = (data.whatsappClick && data.whatsappClick.rows) || [];
      if(!waRows.length){ waShEl.innerHTML = '<div style="color:rgba(255,255,255,.25);font-size:11px;padding:10px 0;text-align:center">💬 WhatsApp 클릭 데이터 수집 중...</div>'; }
      else {
        var waMax = parseInt(waRows[0].metricValues[0].value||1);
        waShEl.innerHTML = waRows.map(function(r, i){
          var sn = r.dimensionValues[0].value || '(없음)';
          var cat = r.dimensionValues[1] ? r.dimensionValues[1].value : '';
          var ev = parseInt(r.metricValues[0].value||0);
          var pct = Math.round(ev/waMax*100);
          var rankC3 = ['#fbbf24','#94a3b8','#b45309'];
          return '<div style="display:flex;align-items:center;gap:6px">'
            +'<span style="font-size:10px;font-weight:900;color:'+(rankC3[i]||'rgba(255,255,255,.25)')+';min-width:14px">'+(i+1)+'</span>'
            +'<div style="flex:1;overflow:hidden">'
              +'<div style="color:rgba(255,255,255,.85);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">'+sn+'</div>'
              +(cat?'<div style="font-size:10px;color:rgba(255,255,255,.3)">'+cat+'</div>':'')
            +'</div>'
            +'<div style="width:50px;height:5px;background:rgba(255,255,255,.07);border-radius:3px"><div style="height:100%;width:'+pct+'%;background:#25d366;border-radius:3px"></div></div>'
            +'<span style="min-width:20px;text-align:right;color:rgba(255,255,255,.4)">'+ev+'</span>'
            +'</div>';
        }).join('');
      }
    }

    // ── 소스/매체 상세 ──
    var smEl = document.getElementById('an-source-medium');
    if(smEl && data.sourceMedium && data.sourceMedium.rows) {
      var _smRow0=data.sourceMedium.rows[0];var _smMv=_smRow0&&_smRow0.metricValues?_smRow0.metricValues[0]:null;var smMax = parseInt((_smMv?_smMv.value:null)||1);
      smEl.innerHTML = data.sourceMedium.rows.slice(0,8).map(function(r){
        var sm = r.dimensionValues[0].value;
        var sess = parseInt(r.metricValues[0].value||0);
        var pct = Math.round(sess/smMax*100);
        var color = sm.includes('google')?'#FF4D8D':sm.includes('organic')?'#34d399':sm.includes('direct')?'#60a5fa':'#fbbf24';
        return '<div style="display:flex;align-items:center;gap:6px">'
          +'<span style="flex:1;color:rgba(255,255,255,.7);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:110px">'+sm+'</span>'
          +'<div style="width:60px;height:5px;background:rgba(255,255,255,.08);border-radius:3px;flex-shrink:0"><div style="height:100%;width:'+pct+'%;background:'+color+';border-radius:3px"></div></div>'
          +'<span style="color:rgba(255,255,255,.4);min-width:24px;text-align:right">'+sess+'</span>'
          +'</div>';
      }).join('');
    }

    // ── 랜딩페이지 ──
    var landEl = document.getElementById('an-landing');
    if(landEl && data.landingPages && data.landingPages.rows) {
      var _landRow0=data.landingPages.rows[0];var _landMv=_landRow0&&_landRow0.metricValues?_landRow0.metricValues[0]:null;var landMax = parseInt((_landMv?_landMv.value:null)||1);
      landEl.innerHTML = data.landingPages.rows.slice(0,8).map(function(r){
        var path = r.dimensionValues[0].value;
        var sess = parseInt(r.metricValues[0].value||0);
        var _mv1=r.metricValues&&r.metricValues[1]?r.metricValues[1]:null;var bounce = Math.round(parseFloat((_mv1?_mv1.value:0)||0)*100);
        var pct = Math.round(sess/landMax*100);
        var shortPath = path.length > 28 ? path.slice(0,28)+'…' : path;
        return '<div style="display:flex;align-items:center;gap:6px">'
          +'<span style="flex:1;color:rgba(255,255,255,.7);font-size:10px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:110px" title="'+path+'">'+shortPath+'</span>'
          +'<div style="width:50px;height:5px;background:rgba(255,255,255,.08);border-radius:3px;flex-shrink:0"><div style="height:100%;width:'+pct+'%;background:#a78bfa;border-radius:3px"></div></div>'
          +'<span style="color:rgba(255,255,255,.4);min-width:24px;text-align:right">'+sess+'</span>'
          +'</div>';
      }).join('');
    }

  } catch(e) {
    console.error('Analytics load error:', e);
    ['an-users','an-pageviews','an-new-users','an-duration'].forEach(function(id){
      var el = document.getElementById(id);
      if(el) el.textContent = 'ERR';
    });
  }

  // ── 서치콘솔 데이터 별도 로드 ──
  try {
    var scRes = await fetch('/api/search-console?days=' + days);
    var scData = await scRes.json();
    if(scData.error) throw new Error(scData.error);

    var NO_DATA = '<div style="color:rgba(255,255,255,.3);font-size:11px;padding:10px 0;text-align:center">🔍 아직 검색 노출 데이터 없음<br><span style="font-size:10px;opacity:.6">구글 검색에 노출되면 자동으로 표시됩니다</span></div>';

    // 검색어
    var kwEl = document.getElementById('sc-keywords');
    if(kwEl) {
      var kwRows = (scData.keywords && scData.keywords.rows) || [];
      if(kwRows.length === 0) {
        kwEl.innerHTML = NO_DATA;
      } else {
        var kwImprMax = Math.max.apply(null, kwRows.map(function(r){ return r.impressions||0; }));
        kwEl.innerHTML = kwRows.map(function(r, i){
          var q = r.keys[0];
          var clicks = r.clicks, impr = r.impressions;
          var ctr = (r.ctr*100).toFixed(0);
          var pos = parseFloat(r.position.toFixed(1));
          var pct = Math.round(impr/Math.max(kwImprMax,1)*100);
          var posColor = pos<=3?'#34d399':pos<=10?'#fbbf24':pos<=20?'#f97316':'rgba(255,255,255,.3)';
          var rankColors = ['#fbbf24','#94a3b8','#b45309'];
          var opp = pos>=4&&pos<=15&&clicks===0?'<span style="background:rgba(251,191,36,.15);border:1px solid rgba(251,191,36,.3);color:#fbbf24;font-size:8px;padding:1px 4px;border-radius:3px">⚡</span>':'';
          return '<div style="padding:5px 4px;border-bottom:1px solid rgba(255,255,255,.04);display:flex;align-items:center;gap:5px">'
            +'<span style="font-size:10px;font-weight:900;color:'+(rankColors[i]||'rgba(255,255,255,.25)')+';min-width:14px;flex-shrink:0">'+(i+1)+'</span>'
            +'<div style="flex:1;min-width:0">'
            +'<div style="display:flex;align-items:center;gap:3px;margin-bottom:2px">'
            +'<span style="flex:1;color:rgba(255,255,255,.85);font-size:10px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="'+q+'">'+q+'</span>'
            +opp
            +'</div>'
            +'<div style="height:2px;background:rgba(255,255,255,.06);border-radius:2px;margin-bottom:2px"><div style="height:100%;width:'+pct+'%;background:linear-gradient(90deg,#34d399,#60a5fa);border-radius:2px"></div></div>'
            +'<div style="display:flex;gap:6px;font-size:9px;color:rgba(255,255,255,.3)">'
            +'<span style="color:'+posColor+';font-weight:700">'+pos+'위</span>'
            +'<span>'+impr+'노출</span>'
            +'<span style="color:'+(clicks>0?'#34d399':'rgba(255,255,255,.3)')+';font-weight:'+(clicks>0?'700':'400')+'">'+clicks+'클릭</span>'
            +'<span>CTR '+ctr+'%</span>'
            +'</div>'
            +'</div>'
            +'</div>';
        }).join('');
      }
    }

    // 페이지별 검색 유입 (클릭시 키워드 드릴다운)
    var scPgEl = document.getElementById('sc-pages');
    if(scPgEl) {
      var pgRows = (scData.pages && scData.pages.rows) || [];
      if(pgRows.length === 0) {
        scPgEl.innerHTML = NO_DATA;
      } else {
        var pgMax2 = Math.max(pgRows[0].impressions || 1, 1);
        scPgEl.innerHTML = pgRows.map(function(r){
          var fullUrl = r.keys[0];
          var page = fullUrl.replace('https://seoulbeautytrip.com','') || '/';
          var clicks = r.clicks, impr = r.impressions, pos = r.position.toFixed(1);
          var ctr = (r.ctr*100).toFixed(1);
          var pct3 = Math.round(impr/pgMax2*100);
          var shortPage = page.length > 28 ? page.slice(0,28)+'…' : page;
          var posNum = parseFloat(pos);
          var posColor = posNum<=3?'#34d399':posNum<=10?'#fbbf24':posNum<=20?'#f97316':'rgba(255,255,255,.35)';
          var posBg = posNum<=3?'rgba(52,211,153,.1)':posNum<=10?'rgba(251,191,36,.1)':posNum<=20?'rgba(249,115,22,.1)':'rgba(255,255,255,.04)';
          return '<div data-url="'+fullUrl+'" onclick="scDrillPage(this.dataset.url)" class="sc-page-row" style="padding:5px 6px;border-bottom:1px solid rgba(255,255,255,.04);cursor:pointer;border-radius:6px;transition:background .15s;display:flex;align-items:center;gap:5px">'
            +'<div style="min-width:30px;text-align:center;background:'+posBg+';border:1px solid '+posColor+'44;border-radius:5px;padding:2px 1px;flex-shrink:0">'
            +'<div style="font-size:10px;font-weight:900;color:'+posColor+';line-height:1">'+pos+'</div>'
            +'<div style="font-size:7px;color:'+posColor+';opacity:.7">위</div>'
            +'</div>'
            +'<div style="flex:1;min-width:0">'
            +'<div style="font-size:10px;color:rgba(255,255,255,.85);white-space:nowrap;overflow:hidden;text-overflow:ellipsis;margin-bottom:1px" title="'+page+'">'+shortPage+'</div>'
            +'<div style="display:flex;gap:6px;font-size:9px;color:rgba(255,255,255,.3)">'
            +'<span style="color:'+(clicks>0?'#60a5fa':'rgba(255,255,255,.3)')+';font-weight:'+(clicks>0?'700':'400')+'">'+clicks+'클릭</span>'
            +'<span>'+impr+'노출</span>'
            +'<span>CTR '+ctr+'%</span>'
            +'</div>'
            +'</div>'
            +'</div>';
        }).join('');
      }
    }

    // 서치콘솔 국가
    var scCntEl = document.getElementById('sc-countries');
    if(scCntEl) {
      var cntRows = (scData.countries && scData.countries.rows) || [];
      if(cntRows.length === 0) {
        scCntEl.innerHTML = NO_DATA;
      } else {
        var flags2 = {'kor':'🇰🇷','usa':'🇺🇸','jpn':'🇯🇵','chn':'🇨🇳','gbr':'🇬🇧','aus':'🇦🇺','can':'🇨🇦','sgp':'🇸🇬','twn':'🇹🇼','fra':'🇫🇷','deu':'🇩🇪','tha':'🇹🇭','vnm':'🇻🇳'};
        var cntMax2 = cntRows[0].clicks || 1;
        scCntEl.innerHTML = cntRows.map(function(r){
          var cc = r.keys[0];
          var flag2 = flags2[cc] || '🌍';
          var clicks2 = r.clicks, impr2 = r.impressions;
          var pct4 = Math.round(clicks2/Math.max(cntMax2,1)*100);
          return '<div style="display:flex;align-items:center;gap:5px">'
            +'<span>'+flag2+'</span>'
            +'<span style="flex:1;color:rgba(255,255,255,.7);text-transform:uppercase;font-size:10px">'+cc+'</span>'
            +'<div style="width:50px;height:4px;background:rgba(255,255,255,.08);border-radius:2px"><div style="height:100%;width:'+pct4+'%;background:#34d399;border-radius:2px"></div></div>'
            +'<span style="color:rgba(255,255,255,.4);min-width:20px;text-align:right">'+clicks2+'</span>'
            +'</div>';
        }).join('');
      }
    }

    // 서치콘솔 디바이스
    var scDevEl = document.getElementById('sc-devices');
    if(scDevEl) {
      var devRows = (scData.devices && scData.devices.rows) || [];
      if(devRows.length === 0) {
        scDevEl.innerHTML = NO_DATA;
      } else {
        var devIcons2 = {MOBILE:'📱',DESKTOP:'💻',TABLET:'📟'};
        var devTotal2 = devRows.reduce(function(s,r){return s+r.clicks;},0);
        scDevEl.innerHTML = devRows.map(function(r){
          var dev = r.keys[0];
          var clicks3 = r.clicks;
          var pct5 = devTotal2>0?Math.round(clicks3/devTotal2*100):0;
          return '<div style="display:flex;align-items:center;gap:6px">'
            +'<span>'+(devIcons2[dev]||'🖥')+'</span>'
            +'<span style="flex:1;color:rgba(255,255,255,.7);font-size:11px">'+dev+'</span>'
            +'<span style="color:#fbbf24;font-weight:700">'+pct5+'%</span>'
            +'<span style="color:rgba(255,255,255,.3);font-size:10px">('+clicks3+')</span>'
            +'</div>';
        }).join('');
      }
    }

  } catch(scErr) {
    console.warn('Search Console load error:', scErr);
    ['sc-keywords','sc-pages','sc-countries','sc-devices'].forEach(function(id){
      var el = document.getElementById(id);
      if(el) el.innerHTML = '<div style="color:rgba(255,255,255,.2);font-size:10px">서치콘솔 데이터 없음</div>';
    });
  }
};

// ── 페이지 키워드 드릴다운 ──
window.scDrillPage = async function(fullUrl) {
  var panel = document.getElementById('sc-page-drill');
  var pageLabel = document.getElementById('sc-drill-page');
  var kwEl = document.getElementById('sc-drill-keywords');
  if(!panel || !kwEl) return;

  var shortPath = fullUrl.replace('https://seoulbeautytrip.com','') || '/';
  panel.style.display = 'block';
  if(pageLabel) pageLabel.textContent = shortPath;
  kwEl.innerHTML = '<div style="color:rgba(255,255,255,.3);text-align:center;padding:10px"><i class="fas fa-spinner fa-spin"></i> 키워드 불러오는 중...</div>';

  // 패널로 스크롤
  panel.scrollIntoView({ behavior: 'smooth', block: 'nearest' });

  try {
    var days = document.getElementById('sc-days') ? document.getElementById('sc-days').value : '28';
    var res = await fetch('/api/search-console/page-keywords?page=' + encodeURIComponent(fullUrl) + '&days=' + days);
    var data = await res.json();
    if(data.error) throw new Error(data.error);

    var rows = (data.keywords && data.keywords.rows) || [];
    if(rows.length === 0) {
      kwEl.innerHTML = '<div style="color:rgba(255,255,255,.35);text-align:center;padding:14px 10px;font-size:11px;line-height:1.6">'
        + '<div style="font-size:18px;margin-bottom:6px">📊</div>'
        + '키워드 세부 데이터가 없습니다<br>'
        + '<span style="font-size:10px;opacity:.7">GSC는 노출 횟수가 적은 페이지의<br>키워드별 데이터를 제공하지 않습니다<br>(프라이버시 임계값 정책)</span>'
        + '</div>';
      return;
    }

    var maxImpr = Math.max(rows[0].impressions || 1, 1);
    kwEl.innerHTML = rows.map(function(r, i) {
      var q = r.keys[0];
      var clicks = r.clicks, impr = r.impressions;
      var ctr = (r.ctr * 100).toFixed(1);
      var pos = r.position.toFixed(1);
      var posNum = parseFloat(pos);
      // 순위별 색상 + 배지
      var posColor = posNum <= 3 ? '#34d399' : posNum <= 10 ? '#fbbf24' : posNum <= 20 ? '#f97316' : 'rgba(255,255,255,.35)';
      var posBg   = posNum <= 3 ? 'rgba(52,211,153,.12)' : posNum <= 10 ? 'rgba(251,191,36,.12)' : posNum <= 20 ? 'rgba(249,115,22,.12)' : 'rgba(255,255,255,.06)';
      var opp = posNum >= 4 && posNum <= 15 && clicks === 0 ? '<span style="background:rgba(251,191,36,.15);border:1px solid rgba(251,191,36,.3);color:#fbbf24;font-size:9px;padding:1px 5px;border-radius:4px">⚡ 기회</span>' : '';
      var pct = Math.round(impr / maxImpr * 100);
      return '<div style="padding:7px 6px;border-bottom:1px solid rgba(255,255,255,.05);display:flex;align-items:flex-start;gap:7px">'
        // 순위 배지 (왼쪽 고정)
        + '<div style="min-width:34px;text-align:center;background:' + posBg + ';border:1px solid ' + posColor + '44;border-radius:6px;padding:3px 2px;flex-shrink:0">'
        +   '<div style="font-size:11px;font-weight:900;color:' + posColor + ';line-height:1">' + pos + '</div>'
        +   '<div style="font-size:8px;color:' + posColor + ';opacity:.7;line-height:1;margin-top:1px">위</div>'
        + '</div>'
        // 키워드 + 지표
        + '<div style="flex:1;min-width:0">'
        +   '<div style="display:flex;align-items:center;gap:5px;margin-bottom:4px;flex-wrap:wrap">'
        +     '<span style="flex:1;color:rgba(255,255,255,.9);font-size:11px;font-weight:600;word-break:break-all">' + q + '</span>'
        +     opp
        +   '</div>'
        +   '<div style="display:flex;align-items:center;gap:8px;font-size:10px;color:rgba(255,255,255,.4)">'
        +     '<span><span style="color:#34d399;font-weight:700">' + clicks + '</span> 클릭</span>'
        +     '<span><span style="color:rgba(255,255,255,.6)">' + impr + '</span> 노출</span>'
        +     '<span>CTR <span style="color:#60a5fa">' + ctr + '%</span></span>'
        +   '</div>'
        +   '<div style="margin-top:4px;height:2px;background:rgba(255,255,255,.06);border-radius:2px">'
        +     '<div style="height:100%;width:' + pct + '%;background:linear-gradient(90deg,#818cf8,#60a5fa);border-radius:2px"></div>'
        +   '</div>'
        + '</div>'
        + '</div>';
    }).join('');
  } catch(e) {
    kwEl.innerHTML = '<div style="color:#f87171;text-align:center;padding:10px;font-size:11px">오류: ' + e.message + '</div>';
  }
};

